const a = [
  {"id":2830,"text":"Which of the following is incorrect regarding the mechanism of action of steroid hormones?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 920.","responses":[{"text":"They involve the adenylyl cyclase pathway","correct":true,"visible":false},{"text":"They activate transcription factors","correct":false,"visible":false},{"text":"They have cytoplasmic receptors","correct":false,"visible":false},{"text":"They act on the genetic machinery of the cell","correct":false,"visible":false},{"text":"They have nuclear receptors","correct":false,"visible":false}]},{"id":2836,"text":"The islets of Langerhans are developed in which month of fetal life?","explanation":"The islets of Langerhans, which are the endocrine portions of the pancreas responsible for producing and releasing hormones like insulin and glucagon, start to develop during the **third month** of fetal life.\r\n\r\nDuring fetal development, the pancreas originates from two buds, the dorsal and ventral pancreatic buds. Around the third month, these buds undergo significant growth, branching, and differentiation. The islets of Langerhans emerge as clusters of specialized endocrine cells within the pancreatic tissue.\r\n\r\nThese islets continue to mature and develop throughout fetal life and postnatally. The proper development and function of the islets of Langerhans are crucial for regulating blood glucose levels and maintaining overall glucose homeostasis in the body.","reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 244.","responses":[{"text":"Fourth month","correct":false,"visible":false},{"text":"Sixth month","correct":false,"visible":false},{"text":"Fifth month","correct":false,"visible":false},{"text":"Third month","correct":true,"visible":false},{"text":"Second month","correct":false,"visible":false}]},{"id":2838,"text":"All catecholamines are derived from which of the following amino acids?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 285.","responses":[{"text":"Histidine","correct":false,"visible":false},{"text":"Arginine","correct":false,"visible":false},{"text":"Tryptophan","correct":false,"visible":false},{"text":"Valine","correct":false,"visible":false},{"text":"Tyrosine","correct":true,"visible":false}]},{"id":2852,"text":"What is the recommended daily intake of calcium?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 399.","responses":[{"text":"800 mg","correct":false,"visible":false},{"text":"600 mg","correct":false,"visible":false},{"text":"1,000 mg","correct":true,"visible":false},{"text":"400 mg","correct":false,"visible":false},{"text":"500 mg","correct":false,"visible":false}]},{"id":2853,"text":"What is the percentage of body calcium stored in teeth and bones?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 991.","responses":[{"text":"95%","correct":false,"visible":false},{"text":"99%","correct":true,"visible":false},{"text":"85%","correct":false,"visible":false},{"text":"80%","correct":false,"visible":false},{"text":"90%","correct":false,"visible":false}]},{"id":2871,"text":"Exophthalmos is most strongly associated with which of the following pathologies?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 1089, 1090.","responses":[{"text":"Conn syndrome","correct":false,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Graves disease","correct":true,"visible":false},{"text":"Hypoparathyroidism","correct":false,"visible":false}]},{"id":2878,"text":"What is the number of amino acids found in the structure of growth hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 898.","responses":[{"text":"191","correct":true,"visible":false},{"text":"89","correct":false,"visible":false},{"text":"69","correct":false,"visible":false},{"text":"10","correct":false,"visible":false},{"text":"112","correct":false,"visible":false}]},{"id":2880,"text":"What is the number of amino acids found in somatostatin?","explanation":null,"reference":null,"responses":[{"text":"89","correct":false,"visible":false},{"text":"14","correct":true,"visible":false},{"text":"69","correct":false,"visible":false},{"text":"10","correct":false,"visible":false},{"text":"191","correct":false,"visible":false}]},{"id":2884,"text":"Which of the following is decreased by somatostatin?","explanation":"**Somatostatin**, also known as growth hormone-inhibiting hormone (GHIH), is a peptide hormone produced by the delta cells of the pancreas and certain other tissues in the body. It exerts inhibitory effects on various physiological processes, including the regulation of hormone secretion.\r\n\r\nOne of the main actions of somatostatin is the inhibition of the secretion of both **insulin** and **glucagon**. Insulin is a hormone produced by beta cells in the pancreas and is responsible for lowering blood glucose levels by promoting the uptake and utilization of glucose by cells. Glucagon, on the other hand, is produced by alpha cells in the pancreas and increases blood glucose levels by promoting the breakdown of glycogen into glucose and stimulating gluconeogenesis.\r\n\r\nBy inhibiting the secretion of both insulin and glucagon, somatostatin helps maintain stable blood glucose levels and prevents wide fluctuations in glucose concentration.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 983.","responses":[{"text":"Aldosterone","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false},{"text":"Cortisol","correct":false,"visible":false},{"text":"Insulin","correct":false,"visible":false},{"text":"Both insulin and glucagon","correct":true,"visible":false}]},{"id":2888,"text":"What shape are the follicular cells of the thyroid gland when they are highly active?","explanation":"When the follicular cells of the thyroid gland are highly active, they exhibit a **columnar** shape.\r\n\r\nThe thyroid gland is responsible for producing thyroid hormones, mainly thyroxine (T4) and triiodothyronine (T3), which play a vital role in regulating metabolism, growth, and development in the body. The synthesis and secretion of these hormones occur within the thyroid follicles.\r\n\r\nDuring periods of increased hormonal activity, such as in response to thyroid-stimulating hormone (TSH) from the pituitary gland, the follicular cells become highly active. They undergo morphological changes and become taller and more columnar in shape. This change is often observed during periods of thyroid hormone synthesis and release.\r\n\r\nThe columnar shape of the follicular cells allows for increased surface area, facilitating the uptake of iodine and the synthesis of thyroid hormones within the thyroid follicles.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 430.","responses":[{"text":"Columnar","correct":true,"visible":false},{"text":"Cuboidal","correct":false,"visible":false},{"text":"Pseudostratified columnar","correct":false,"visible":false},{"text":"Squamous","correct":false,"visible":false},{"text":"Stratified cuboidal","correct":false,"visible":false}]},{"id":2892,"text":"Which of the following drugs acts to inhibit glucose absorption in the small intestine?","explanation":null,"reference":null,"responses":[{"text":"Glucosidase inhibitors","correct":true,"visible":false},{"text":"Insulin aspart","correct":false,"visible":false},{"text":"Glipazide","correct":false,"visible":false},{"text":"Metformin","correct":false,"visible":false},{"text":"Exogenous glucose","correct":false,"visible":false}]},{"id":2893,"text":"What process does glucagon enhance the most?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 982.","responses":[{"text":"Hepatic glycogenolysis","correct":true,"visible":false},{"text":"Hepatic glycogenesis","correct":false,"visible":false},{"text":"Protein formation","correct":false,"visible":false},{"text":"Fatty acid synthesis","correct":false,"visible":false},{"text":"Amino acids uptake","correct":false,"visible":false}]},{"id":2894,"text":"Which cell organelle synthesizes steroid hormones?","explanation":null,"reference":null,"responses":[{"text":"Golgi body","correct":false,"visible":false},{"text":"Ribosomes","correct":false,"visible":false},{"text":"Smooth endoplasmic reticulum","correct":true,"visible":false},{"text":"Rough endoplasmic reticulum","correct":false,"visible":false},{"text":"Nucleus","correct":false,"visible":false}]},{"id":2897,"text":"What is the best diagnostic test for Cushing syndrome?","explanation":null,"reference":null,"responses":[{"text":"Adrenocorticotropic hormone(ACTH) levels test","correct":false,"visible":false},{"text":"24-hour urine collection for analysis of free cortisol","correct":true,"visible":false},{"text":"Corticotropin-releasing hormone(CRH) stimulation test","correct":false,"visible":false},{"text":"High-dose dexamethasone suppression test","correct":false,"visible":false},{"text":"Serum cortisol levels test","correct":false,"visible":false}]},{"id":2898,"text":"80% secretion of the adrenal medulla consists of what substance?","explanation":null,"reference":null,"responses":[{"text":"Testosterone","correct":false,"visible":false},{"text":"Noradrenaline/Norepinephrine","correct":false,"visible":false},{"text":"Cortisol","correct":false,"visible":false},{"text":"Adrenaline/Epinephrine","correct":true,"visible":false},{"text":"Aldosterone","correct":false,"visible":false}]},{"id":2899,"text":"What is the test for Graves disease?","explanation":null,"reference":null,"responses":[{"text":"T4 levels","correct":false,"visible":false},{"text":"T3 levels","correct":false,"visible":false},{"text":"Corticotropin-releasing hormone (CRH) levels","correct":false,"visible":false},{"text":"Thyroid stimulating hormone (TSH) concentration","correct":true,"visible":false},{"text":"Adrenocorticotropic hormone (ACTH) levels","correct":false,"visible":false}]},{"id":2900,"text":"The adrenal cortex secretes how many distinct types of hormones?","explanation":null,"reference":null,"responses":[{"text":"2","correct":false,"visible":false},{"text":"3","correct":true,"visible":false},{"text":"4","correct":false,"visible":false},{"text":"5","correct":false,"visible":false},{"text":"6","correct":false,"visible":false}]},{"id":2901,"text":"A woman comes to the outpatient department with a complaint of being restless for the past 3 months. She has a single painless swelling in her neck. What is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Iodine deficiency","correct":false,"visible":false},{"text":"Subacute lymphocytic thyroiditis","correct":true,"visible":false},{"text":"Toxic multinodular goiter","correct":false,"visible":false},{"text":"Subacute granulomatous thyroiditis","correct":false,"visible":false},{"text":"Multinodular goiter","correct":false,"visible":false}]},{"id":2902,"text":"What quantity of iodine is required per day for the normal production of thyroid hormones?","explanation":null,"reference":null,"responses":[{"text":"150 microgram","correct":true,"visible":false},{"text":"250 microgram","correct":false,"visible":false},{"text":"500 microgram","correct":false,"visible":false},{"text":"50 microgram","correct":false,"visible":false},{"text":"350 microgram","correct":false,"visible":false}]},{"id":2903,"text":"What type of cells secrete insulin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 974.","responses":[{"text":"PP cells","correct":false,"visible":false},{"text":"Alpha cells","correct":false,"visible":false},{"text":"Delta cells","correct":false,"visible":false},{"text":"I cells","correct":false,"visible":false},{"text":"Beta cells","correct":true,"visible":false}]},{"id":2904,"text":"What vertebral level is the thyroid gland found at?","explanation":null,"reference":null,"responses":[{"text":"C8-T2","correct":false,"visible":false},{"text":"C1-C4","correct":false,"visible":false},{"text":"C6-T2","correct":false,"visible":false},{"text":"C5-T1","correct":true,"visible":false},{"text":"C4-C8","correct":false,"visible":false}]},{"id":2905,"text":"Which of the following statements is wrong about the Sheehan syndrome?","explanation":null,"reference":null,"responses":[{"text":"It leads to pituitary necrosis","correct":false,"visible":false},{"text":"It is associated with antepartum hemorrhage","correct":true,"visible":false},{"text":"It can present as cold intolerance","correct":false,"visible":false},{"text":"It is associated with postpartum hemorrhage","correct":false,"visible":false},{"text":"It results from ischemia to pituitary gland","correct":false,"visible":false}]},{"id":2908,"text":"What is the function of adenylyl cyclase?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 923.","responses":[{"text":"Conversion of ATP to cAMP","correct":true,"visible":false},{"text":"Activation of G protein","correct":false,"visible":false},{"text":"Conversion of ATP to AMP","correct":false,"visible":false},{"text":"Conversion of ATP to cGMP","correct":false,"visible":false},{"text":"Conversion of cAMP to ATP","correct":false,"visible":false}]},{"id":2912,"text":"Which of the following is an accurate and simple parameter, requiring no calculation, to assess central obesity?","explanation":"**Waist circumference** is an accurate and simple parameter that requires no calculation to assess central obesity. Central obesity refers to the excessive accumulation of fat in the abdominal area and is associated with an increased risk of various health conditions, including type 2 diabetes, cardiovascular diseases, and metabolic syndrome.\r\n\r\nTo measure waist circumference, a flexible measuring tape is placed around the waist, just above the hip bones. The measurement is taken at the end of normal expiration, with the tape snug but not compressing the skin.\r\n\r\nCentral obesity, as indicated by an elevated waist circumference, is an essential component of metabolic syndrome, which includes a cluster of risk factors for cardiovascular diseases and type 2 diabetes. It is a simple and valuable screening tool for identifying individuals at higher risk of obesity-related health issues.","reference":"(1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 700, 744.\r\n\r\n(2) Schunkert H, Markus MRP, Stritzke J, Preedy VR. Waist circumference and cardiovascular risk. Handbook of Anthropometry: Physical Measures of Human Form in Health and Disease. Published 2012. Accessed June 20, 2022. https://doi.org/10.1007/978-1-4419-1788-1_131","responses":[{"text":"Waist circumference","correct":true,"visible":false},{"text":"Weight-to-height ratio","correct":false,"visible":false},{"text":"Body mass index","correct":false,"visible":false},{"text":"Weight measurement","correct":false,"visible":false},{"text":"Blood cholesterol levels","correct":false,"visible":false}]},{"id":2918,"text":"Iodine uptake in thyroid cells takes place through which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 941.","responses":[{"text":"Iodide-chloride symporter","correct":false,"visible":false},{"text":"Potassium-iodide antiporter","correct":false,"visible":false},{"text":"Sodium-iodide symporter","correct":true,"visible":false},{"text":"Potassium-iodide symporter","correct":false,"visible":false},{"text":"Sodium-iodide antiporter","correct":false,"visible":false}]},{"id":2966,"text":"Regarding the squamous epithelium of the thyroid, which of the following statements is false?","explanation":null,"reference":null,"responses":[{"text":"It is accompanied by zero to low colloid","correct":false,"visible":false},{"text":"It can be stratified squamous epithelium","correct":false,"visible":false},{"text":"It shows in a hyperactive thyroid","correct":true,"visible":false},{"text":"It transitions to columnar in hyperactive thyroid","correct":false,"visible":false},{"text":"It shows in a hypoactive thyroid","correct":false,"visible":false}]},{"id":2968,"text":"Iodine trapping and its subsequent use do not include which of the following?","explanation":null,"reference":null,"responses":[{"text":"Synthesis of thyroglobulin","correct":false,"visible":false},{"text":"Ca2+","correct":true,"visible":false},{"text":"Sodium co-transport","correct":false,"visible":false},{"text":"ATP","correct":false,"visible":false},{"text":"Peroxidase","correct":false,"visible":false}]},{"id":2969,"text":"Which of the following cell types are not a part of the anterior pituitary?","explanation":null,"reference":null,"responses":[{"text":"Mammotropes","correct":false,"visible":false},{"text":"Melanocytes","correct":true,"visible":false},{"text":"Somatotropes","correct":false,"visible":false},{"text":"Thyrotropes","correct":false,"visible":false},{"text":"Gonadotropes","correct":false,"visible":false}]},{"id":2971,"text":"Which of the following hormones does not use cAMP as a second messenger?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 924.","responses":[{"text":"Estrogen","correct":true,"visible":false},{"text":"Thyroid-stimulating hormone (TSH)","correct":false,"visible":false},{"text":"Follicle-stimulating hormone (FSH)","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone (ACTH)","correct":false,"visible":false}]},{"id":2972,"text":"What is the mechanism of action for adrenocorticotropic hormone (ACTH)?","explanation":null,"reference":null,"responses":[{"text":"IP3 linked pathway","correct":false,"visible":false},{"text":"cAMP as a second messenger","correct":true,"visible":false},{"text":"Phospholipase linked pathway","correct":false,"visible":false},{"text":"Intracellular receptor pathway","correct":false,"visible":false},{"text":"Tyrosine kinase linked","correct":false,"visible":false}]},{"id":2973,"text":"What are the glial cells of the posterior pituitary also known as?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 421.","responses":[{"text":"Melanocytes","correct":false,"visible":false},{"text":"Gonadotropes","correct":false,"visible":false},{"text":"Somatotropes","correct":false,"visible":false},{"text":"Mammotropes","correct":false,"visible":false},{"text":"Pituicytes","correct":true,"visible":false}]},{"id":2974,"text":"Which of the following is the most common pituitary disease?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1067.","responses":[{"text":"Pituitary metastatic tumors","correct":false,"visible":false},{"text":"Sarcoidosis","correct":false,"visible":false},{"text":"Pituitary apoplexy","correct":false,"visible":false},{"text":"Empty sella syndrome","correct":false,"visible":false},{"text":"Pituitary adenoma","correct":true,"visible":false}]},{"id":2977,"text":"Parathyroid hormone enhances 1-alpha-hydroxylase activity which in turn stimulates which of the following processes?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 390.","responses":[{"text":"Vitamin D synthesis","correct":true,"visible":false},{"text":"Vitamin D absorption","correct":false,"visible":false},{"text":"Vitamin D catabolism","correct":false,"visible":false},{"text":"Calcium metabolism","correct":false,"visible":false},{"text":"Calcitonin synthesis","correct":false,"visible":false}]},{"id":2978,"text":"Oxytocin and vasopressin are produced by which of the following structures?","explanation":null,"reference":null,"responses":[{"text":"Anterior pituitary","correct":false,"visible":false},{"text":"Adrenal gland","correct":false,"visible":false},{"text":"Middle pituitary","correct":false,"visible":false},{"text":"Hypothalamus","correct":true,"visible":false},{"text":"Posterior pituitary","correct":false,"visible":false}]},{"id":2980,"text":"Which statement is wrong regarding the thyroid gland?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 430.","responses":[{"text":"It is supplied by the inferior thyroid artery","correct":false,"visible":false},{"text":"It develops after birth","correct":true,"visible":false},{"text":"It may form a thyroglossal duct","correct":false,"visible":false},{"text":"It is at the vertebral level of C5-T1","correct":false,"visible":false},{"text":"It develops from a diverticulum in the tongue","correct":false,"visible":false}]},{"id":2981,"text":"What layer(s) is the adrenal gland derived from?","explanation":null,"reference":null,"responses":[{"text":"Only mesoderm","correct":false,"visible":false},{"text":"Only endoderm","correct":false,"visible":false},{"text":"Ectoderm and mesoderm","correct":true,"visible":false},{"text":"Ectoderm and endoderm","correct":false,"visible":false},{"text":"Only ectoderm","correct":false,"visible":false}]},{"id":2982,"text":"What is the first step in thyroid hormone synthesis?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 908.","responses":[{"text":"Iodide trapping","correct":true,"visible":false},{"text":"Deiodination","correct":false,"visible":false},{"text":"Splitting","correct":false,"visible":false},{"text":"Organification","correct":false,"visible":false},{"text":"Conjugation","correct":false,"visible":false}]},{"id":2983,"text":"Prolactinoma is a tumor of what type of cells?","explanation":null,"reference":null,"responses":[{"text":"Gonadotropes","correct":false,"visible":false},{"text":"Somatotropes","correct":false,"visible":false},{"text":"Mammotropes","correct":true,"visible":false},{"text":"Mammary gland cells","correct":false,"visible":false},{"text":"Corticotropes","correct":false,"visible":false}]},{"id":2984,"text":"Which polypeptide is made up of 14 amino acids and is also found in the pancreas?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 421.","responses":[{"text":"Somatostatin","correct":true,"visible":false},{"text":"Glucagon","correct":false,"visible":false},{"text":"Cortisol","correct":false,"visible":false},{"text":"Pancreatic polypeptide","correct":false,"visible":false},{"text":"Insulin","correct":false,"visible":false}]},{"id":2987,"text":"Which one of the following is an endocrine gland?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 413.","responses":[{"text":"Spleen","correct":false,"visible":false},{"text":"Tongue","correct":false,"visible":false},{"text":"Pituitary","correct":true,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Skin","correct":false,"visible":false}]},{"id":2988,"text":"What is the action of steroid hormone when it binds to its target cell receptor?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 925.","responses":[{"text":"It causes the formation of releasing hormones","correct":false,"visible":false},{"text":"It causes the formation of cyclic AMP","correct":false,"visible":false},{"text":"It turns specific genes of the nuclear DNA on or off","correct":true,"visible":false},{"text":"It causes the formation of cyclic GMP","correct":false,"visible":false},{"text":"It is converted into cholesterol, which acts as a second messenger","correct":false,"visible":false}]},{"id":2989,"text":"What will be the effect on endogenous cortisol and ACTH when exogenous cortisol is given?","explanation":null,"reference":null,"responses":[{"text":"Endogenous cortical decrease and ACTH increase","correct":false,"visible":false},{"text":"Both increase","correct":false,"visible":false},{"text":"None","correct":false,"visible":false},{"text":"Endogenous cortical increase and ACTH decrease","correct":false,"visible":false},{"text":"Both decrease","correct":true,"visible":false}]},{"id":2992,"text":"Which of the following substances is the precursor for all steroid hormones?","explanation":"**Cholesterol** is the precursor for all steroid hormones. It serves as the starting material from which the body synthesizes various steroid hormones, including glucocorticoids, mineralocorticoids, and sex hormones (estrogens, progesterone, and androgens).\r\n\r\nThe biosynthesis of steroid hormones begins with the conversion of cholesterol to **pregnenolone** by the enzyme cytochrome P450 side-chain cleavage enzyme (P450scc). Pregnenolone then serves as the common precursor for the synthesis of other specific steroid hormones. Depending on the tissue and the specific enzymes present, pregnenolone can be converted into different hormones.\r\n\r\nFor example, in the adrenal cortex, pregnenolone is further converted to mineralocorticoids (aldosterone) and glucocorticoids (cortisol). In the gonads (ovaries and testes), it is converted to androgens (testosterone) and estrogens (estradiol).","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 237.","responses":[{"text":"Pregnenolone","correct":false,"visible":false},{"text":"Pregnanediol","correct":false,"visible":false},{"text":"Estrogen","correct":false,"visible":false},{"text":"Cholesterol","correct":true,"visible":false},{"text":"Valine","correct":false,"visible":false}]},{"id":2995,"text":"What part of the nervous system is activated in a fight or flight situation?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 739.","responses":[{"text":"Special senses","correct":false,"visible":false},{"text":"Somatic nervous system","correct":false,"visible":false},{"text":"Parasympathetic part of autonomic nervous system","correct":false,"visible":false},{"text":"Enteric nervous system","correct":false,"visible":false},{"text":"Sympathetic part of autonomic nervous system","correct":true,"visible":false}]},{"id":2998,"text":"What are the hormone-secreting cells of the adrenal medulla known as?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 425, 427.","responses":[{"text":"Pituicytes","correct":false,"visible":false},{"text":"Corticocytes","correct":false,"visible":false},{"text":"Chromaffin cells","correct":true,"visible":false},{"text":"Somatotropes","correct":false,"visible":false},{"text":"Melanocytes","correct":false,"visible":false}]},{"id":2999,"text":"Which statement is correct regarding insulin's structure?","explanation":"Insulin is a **heterodimeric protein** hormone that consists of two peptide chains linked together by disulfide bonds. It is synthesized as a single-chain precursor called proinsulin, which is then cleaved to form the active insulin molecule.\r\n\r\nThe two peptide chains in insulin are called the A chain and the B chain. The A chain contains 21 amino acids, and the B chain contains 30 amino acids. These two chains are held together by two interchain disulfide bonds, which give insulin its characteristic three-dimensional structure.\r\n\r\nInsulin is produced and secreted by the beta cells of the pancreas in response to elevated blood glucose levels. It plays a crucial role in regulating glucose metabolism by promoting the uptake of glucose into cells and the storage of glucose as glycogen in the liver and muscle tissues.","reference":"(1) Production of a novel heterodimeric two-chain insulin-Fc fusion protein. Accessed June 18, 2022. https://academic.oup.com/peds/article/doi/10.1093/protein/gzaa026/5959880\r\n\r\n(2) Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 308.","responses":[{"text":"It is a steroid hormone","correct":false,"visible":false},{"text":"It is a heterodimeric protein","correct":true,"visible":false},{"text":"It is a glycolipid","correct":false,"visible":false},{"text":"It is an amino acid","correct":false,"visible":false},{"text":"It is a homodimeric protein","correct":false,"visible":false}]},{"id":3001,"text":"Secondary hyperparathyroidism can arise due to which of the following?","explanation":null,"reference":null,"responses":[{"text":"1α-hydroxylase deficiency","correct":true,"visible":false},{"text":"21α-hydroxylase deficiency","correct":false,"visible":false},{"text":"Deficiency of both 1α-hydroxylase and 21α-hydroxylase","correct":false,"visible":false},{"text":"17α-hydroxylase deficiency","correct":false,"visible":false},{"text":"1α-hydroxylase overexpression","correct":false,"visible":false}]},{"id":3002,"text":"Which of the following conditions will decrease the rate of secretion of thyrotropin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 896.","responses":[{"text":"Concentration of iodine in blood is low","correct":false,"visible":false},{"text":"Concentration of thyroid hormones in blood is low","correct":false,"visible":false},{"text":"Concentration of iodine in blood is high","correct":false,"visible":false},{"text":"Concentration of iodine in blood is normal","correct":false,"visible":false},{"text":"Concentration of thyroid hormones in blood is high","correct":true,"visible":false}]},{"id":3004,"text":"Excessive parathyroid hormone causes which of the following conditions?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 965.","responses":[{"text":"Bone resorption","correct":true,"visible":false},{"text":"Collagen synthesis","correct":false,"visible":false},{"text":"Collagen degradation","correct":false,"visible":false},{"text":"Increased vitamin C uptake","correct":false,"visible":false},{"text":"Bone formation","correct":false,"visible":false}]},{"id":3005,"text":"While reading the magnetic resonance imaging (MRI) report of a hypertensive patient, a radiologist noted that a vascular lesion was affecting the hypophyseal portal system. Which artery forms this portal system?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 416-417.","responses":[{"text":"Posterior communicating artery","correct":false,"visible":false},{"text":"Basilar artery","correct":false,"visible":false},{"text":"Ophthalmic artery","correct":false,"visible":false},{"text":"Superior hypophyseal artery","correct":true,"visible":false},{"text":"Anterior inferior cerebellar artery","correct":false,"visible":false}]},{"id":3012,"text":"A 62-year-old male presents to the clinic with complaints of weight gain and lethargy. He suffers from hypertension and ischemic heart disease, for which he is taking drugs. His TSH and FT4 levels are 21 mIU/L and 0.02 ng/dL, respectively. Considering drug-induced hypothyroidism, which of the following drug might be the most common cause?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 647.","responses":[{"text":"Interferon","correct":false,"visible":false},{"text":"Sulphasalazine","correct":false,"visible":false},{"text":"Interleukin blockers","correct":false,"visible":false},{"text":"Phenylbutazone","correct":false,"visible":false},{"text":"Amiodarone","correct":true,"visible":false}]},{"id":3016,"text":"A pathologist is observing a specimen from the parathyroid gland. He notices that the glandular cells are small with rounded central nuclei and pale eosinophilic or clear cytoplasm. These cells are arranged in clusters and form 80% of the total volume in normal adults. Which is the most likely cell type that the pathologist observed?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 433.","responses":[{"text":"Oxyphil cells","correct":false,"visible":false},{"text":"Follicular cells","correct":false,"visible":false},{"text":"C cells","correct":false,"visible":false},{"text":"Chief/principal cells","correct":true,"visible":false},{"text":"Clear cells","correct":false,"visible":false}]},{"id":3019,"text":"What is the most important component of metabolic syndrome according to the International Diabetes Federation?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 447-448.","responses":[{"text":"Visceral obesity","correct":true,"visible":false},{"text":"Impaired glucose tolerance test","correct":false,"visible":false},{"text":"Hypertriglyceridemia","correct":false,"visible":false},{"text":"Low HDL cholesterol","correct":false,"visible":false},{"text":"Hypertension","correct":false,"visible":false}]},{"id":3021,"text":"What is the most common enzyme defect in congenital adrenal hyperplasia?","explanation":null,"reference":null,"responses":[{"text":"18-Hydroxylase","correct":false,"visible":false},{"text":"17,20-lyase","correct":false,"visible":false},{"text":"11β-Hydroxylase","correct":false,"visible":false},{"text":"17α-Hydroxylase","correct":false,"visible":false},{"text":"21-Hydroxylase","correct":true,"visible":false}]},{"id":3022,"text":"Which of the following is the rate-limiting enzyme in steroidogenesis?","explanation":null,"reference":null,"responses":[{"text":"11β-Hydroxylase","correct":false,"visible":false},{"text":"Desmolase","correct":true,"visible":false},{"text":"3β-Hydroxysteroid dehydrogenase","correct":false,"visible":false},{"text":"17α-Hydroxylase","correct":false,"visible":false},{"text":"21-Hydroxylase","correct":false,"visible":false}]},{"id":3023,"text":"What is the number of amino acids in glucagon?","explanation":null,"reference":null,"responses":[{"text":"30","correct":false,"visible":false},{"text":"21","correct":false,"visible":false},{"text":"40","correct":false,"visible":false},{"text":"29","correct":true,"visible":false},{"text":"51","correct":false,"visible":false}]},{"id":3025,"text":"Which of the following controls pituitary gland?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 930.","responses":[{"text":"Pons","correct":false,"visible":false},{"text":"Medulla oblongata","correct":false,"visible":false},{"text":"Mammillary bodies","correct":false,"visible":false},{"text":"Hypothalamus","correct":true,"visible":false},{"text":"Stretch receptors","correct":false,"visible":false}]},{"id":3026,"text":"Which of the following is inappropriate about levothyroxine?","explanation":null,"reference":null,"responses":[{"text":"It is usually the first form of choice in patients with hypothyroidism","correct":false,"visible":false},{"text":"It is slower acting than liothyronine","correct":false,"visible":false},{"text":"It has longer half life than liothyronine","correct":false,"visible":false},{"text":"It has a short half-life","correct":true,"visible":false},{"text":"Lower initial doses are administered in older patients with longstanding myxedema","correct":false,"visible":false}]},{"id":3027,"text":"Which of the following is secreted by the posterior pituitary gland?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 917.","responses":[{"text":"Growth hormone and adrenocorticotropic hormone","correct":false,"visible":false},{"text":"Prolactin and oxytocin","correct":false,"visible":false},{"text":"Antidiuretic hormone and prolactin","correct":false,"visible":false},{"text":"Gonadotropin releasing hormone and prolactin","correct":false,"visible":false},{"text":"Antidiuretic hormone and oxytocin","correct":true,"visible":false}]},{"id":3028,"text":"Which of the following is secreted by the paraventricular nucleus?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 938.","responses":[{"text":"Antidiuretic hormone","correct":false,"visible":false},{"text":"Oxytocin","correct":true,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Gonadotropin releasing hormone","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone","correct":false,"visible":false}]},{"id":3029,"text":"Which of the following hormones is a regulator of satiety?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 883.","responses":[{"text":"Cortisol","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone","correct":false,"visible":false},{"text":"Insulin","correct":false,"visible":false},{"text":"Leptin","correct":true,"visible":false},{"text":"Gastrin","correct":false,"visible":false}]},{"id":3030,"text":"Which of the following is incorrect about insulin?","explanation":null,"reference":null,"responses":[{"text":"The alpha chain has 21 amino acids","correct":false,"visible":false},{"text":"The beta chain has 30 amino acids","correct":false,"visible":false},{"text":"Insulin is formed by the beta cells of the islets of Langerhans in the pancreas","correct":false,"visible":false},{"text":"It increases the activity of hormone sensitive lipase","correct":true,"visible":false},{"text":"It is made up of 51 amino acids","correct":false,"visible":false}]},{"id":3031,"text":"Which of the following hormones causes uterine contraction?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 917.","responses":[{"text":"Gonadotropin releasing hormone","correct":false,"visible":false},{"text":"Antidiuretic hormone","correct":false,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone","correct":false,"visible":false},{"text":"Oxytocin","correct":true,"visible":false}]},{"id":3035,"text":"Which of the following cells secretes growth hormone (GH)?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 931.","responses":[{"text":"Gonadotropes","correct":false,"visible":false},{"text":"Somatotropes","correct":true,"visible":false},{"text":"Corticotropes","correct":false,"visible":false},{"text":"Thyrotropes","correct":false,"visible":false},{"text":"Lactotropes","correct":false,"visible":false}]},{"id":3038,"text":"What is the best sign seen in hyperthyroidism?","explanation":null,"reference":null,"responses":[{"text":"Weight gain","correct":false,"visible":false},{"text":"Lethargy","correct":false,"visible":false},{"text":"Bradycardia","correct":false,"visible":false},{"text":"Constipation","correct":false,"visible":false},{"text":"Heat intolerance","correct":true,"visible":false}]},{"id":3039,"text":"Which of the following is inappropriate about the lymphatic drainage of thyroid gland?","explanation":null,"reference":null,"responses":[{"text":"Prelaryngeal","correct":false,"visible":false},{"text":"Pretracheal","correct":false,"visible":false},{"text":"Deep cervical","correct":false,"visible":false},{"text":"Paratracheal","correct":false,"visible":false},{"text":"Superficial cervical","correct":true,"visible":false}]},{"id":3040,"text":"Which of the following is the effect of propylthiouracil on thyroid hormone?","explanation":"Propylthiouracil (PTU) is an antithyroid drug used in the treatment of hyperthyroidism. Its primary mechanism of action involves inhibition of thyroid hormone synthesis.\r\n\r\nSpecifically, PTU exerts its effect on the thyroid gland by inhibiting two key steps in thyroid hormone synthesis:\r\n\r\n1. **Inhibition of oxidation of iodide:** The thyroid gland actively takes up iodide from the bloodstream using the sodium-iodide symporter (NIS) on the apical membrane of thyrocytes. PTU inhibits the enzyme thyroid peroxidase (TPO), which is responsible for the oxidation of iodide to iodine within the thyroid follicular cells. This inhibits the formation of iodine radicals necessary for the synthesis of thyroid hormones.\r\n\r\n2. **Inhibition of coupling of iodine:** After iodine is oxidized, it is attached to tyrosine residues on thyroglobulin, a protein within the colloid of thyroid follicles. PTU further inhibits the enzyme TPO from catalyzing the coupling of iodine residues on thyroglobulin, preventing the formation of T3 and T4 (triiodothyronine and thyroxine).","reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 308.","responses":[{"text":"Hyper activates Na-I symporter","correct":false,"visible":false},{"text":"Hypertrophy of thyroid follicles","correct":false,"visible":false},{"text":"Inhibit T3 release from thyroglobulin","correct":false,"visible":false},{"text":"Inactivates thyroglobulin","correct":false,"visible":false},{"text":"Inhibits oxidation of iodide and coupling of iodine","correct":true,"visible":false}]},{"id":3041,"text":"A girl presents to the outpatient department with enlargement of the right thyroid gland. Which of the following lymph nodes would not be involved?","explanation":null,"reference":null,"responses":[{"text":"Deep cervical","correct":false,"visible":false},{"text":"Prelaryngeal","correct":false,"visible":false},{"text":"Pretracheal","correct":false,"visible":false},{"text":"Superficial cervical","correct":true,"visible":false},{"text":"Paratracheal","correct":false,"visible":false}]},{"id":3043,"text":"Which of the following is the most common cause of congenital hypothyroidism worldwide?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1077.","responses":[{"text":"Cellular atrophy","correct":false,"visible":false},{"text":"Iodine deficiency","correct":true,"visible":false},{"text":"Hashimoto's thyroiditis","correct":false,"visible":false},{"text":"Autoimmune destruction","correct":false,"visible":false},{"text":"Hypercortisolism","correct":false,"visible":false}]},{"id":3048,"text":"What is the mode of inheritance of congenital adrenal hyperplasia?","explanation":null,"reference":null,"responses":[{"text":"X-linked recessive","correct":false,"visible":false},{"text":"X-linked dominant","correct":false,"visible":false},{"text":"Mitochondrial inheritance","correct":false,"visible":false},{"text":"Autosomal dominant","correct":false,"visible":false},{"text":"Autosomal recessive","correct":true,"visible":false}]},{"id":3049,"text":"Regarding the development of pituitary gland, which of the following is true?","explanation":"The pituitary gland, also known as the hypophysis, is a crucial endocrine gland responsible for producing and secreting various hormones that regulate numerous physiological processes in the body. Its development involves the formation of distinct parts derived from different embryonic tissues.\r\n\r\n1. **Hypophyseal Diverticulum:** The pituitary gland develops from a depression of the oral ectoderm known as the hypophyseal diverticulum or Rathke's pouch. During the 3rd week of gestation, this pouch forms as an upward projection from the roof of the stomodeum (primitive mouth cavity).\r\n\r\n2. **Ectodermal Origin:** The hypophyseal diverticulum is purely ectodermal in origin. It is not derived from mesoderm or endoderm. As the embryo continues to develop, the Rathke's pouch undergoes complex processes of invagination, proliferation, and differentiation to give rise to the adenohypophysis (anterior pituitary).\r\n\r\n3. **Pars Nervosa:** The pars nervosa, also known as the neurohypophysis (posterior pituitary), develops from neuroectodermal tissue in the diencephalon known as the infundibulum. Nerve fibers from the hypothalamus grow downward along the infundibulum to establish connections with the pars nervosa.","reference":"Moore KL, Persaud TVN, Torchia M. The Developing Human: Clinically Oriented Embryology. 9th ed. Elsevier; 2011: 409.","responses":[{"text":"The entire gland develops from Rathke's pouch","correct":false,"visible":false},{"text":"It is purely ectodermal in origin","correct":true,"visible":false},{"text":"Hypophyseal diverticulum arises from the floor of stomodeum","correct":false,"visible":false},{"text":"Pars nervosa develops from Rathke's pouch","correct":false,"visible":false},{"text":"The hypophyseal diverticulum loses its connection from the stomodeum by twelfth week","correct":false,"visible":false}]},{"id":3050,"text":"Which of the following is the diagnostic test for acromegaly?","explanation":"Acromegaly is a condition caused by excessive production of growth hormone (GH) in adulthood, usually due to a benign tumor of the pituitary gland. The most commonly used diagnostic test for acromegaly is the **oral glucose tolerance test (OGTT)**.\r\n\r\nDuring the OGTT, the patient is given a standard oral glucose load, and blood samples are taken at regular intervals to measure GH levels. In a person with acromegaly, GH levels fail to suppress appropriately following glucose ingestion. Normally, glucose ingestion should suppress GH secretion. However, in acromegaly, the pituitary tumor continues to release GH, leading to persistent high levels of GH in the blood.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1079.","responses":[{"text":"Glucose tolerance test","correct":true,"visible":false},{"text":"Homocysteine levels","correct":false,"visible":false},{"text":"Liver function test","correct":false,"visible":false},{"text":"Insulin levels","correct":false,"visible":false},{"text":"Somatostatin levels","correct":false,"visible":false}]},{"id":3051,"text":"What is the cut-off for fasting blood glucose level in diabetes?","explanation":null,"reference":null,"responses":[{"text":"250 mg/dl","correct":false,"visible":false},{"text":"100 mg/dl","correct":false,"visible":false},{"text":"126 mg/dl","correct":true,"visible":false},{"text":"80 mg/dl","correct":false,"visible":false},{"text":"140 mg/dl","correct":false,"visible":false}]},{"id":3052,"text":"What is the most common cause of hypoparathyroidism?","explanation":null,"reference":null,"responses":[{"text":"Genetic","correct":false,"visible":false},{"text":"Idiopathic","correct":false,"visible":false},{"text":"Surgery","correct":true,"visible":false},{"text":"Autoimmune","correct":false,"visible":false},{"text":"Congenital","correct":false,"visible":false}]},{"id":3053,"text":"What is the most common cause of hyperparathyroidism?","explanation":null,"reference":null,"responses":[{"text":"Infection","correct":false,"visible":false},{"text":"Hyperplasia","correct":false,"visible":false},{"text":"Autoimmune","correct":false,"visible":false},{"text":"Solitary adenoma","correct":true,"visible":false},{"text":"Carcinoma","correct":false,"visible":false}]},{"id":3054,"text":"Which gland is regarded as the master gland?","explanation":null,"reference":"Dorton AM. The pituitary gland: embryology, physiology, and pathophysiology. Neonatal network: NN. Published March 2000. https://pubmed.ncbi.nlm.nih.gov/11949004/","responses":[{"text":"Pituitary gland","correct":true,"visible":false},{"text":"Thyroid gland","correct":false,"visible":false},{"text":"Adrenal gland","correct":false,"visible":false},{"text":"Pineal gland","correct":false,"visible":false},{"text":"Pancreatic islets","correct":false,"visible":false}]},{"id":3055,"text":"Which antihypertensive drug causes hyperkalemia?","explanation":null,"reference":null,"responses":[{"text":"Furosemide","correct":false,"visible":false},{"text":"Metolazone","correct":false,"visible":false},{"text":"Spironolactone","correct":true,"visible":false},{"text":"Fludrocortisone","correct":false,"visible":false},{"text":"Hydrochlorothiazide","correct":false,"visible":false}]},{"id":3060,"text":"Which of the following is a diagnostic test for pituitary tumors?","explanation":null,"reference":null,"responses":[{"text":"TSH plasma level","correct":false,"visible":false},{"text":"Prolactin level in blood","correct":false,"visible":false},{"text":"ACTH plasma level","correct":false,"visible":false},{"text":"IGF-1 plasma level","correct":false,"visible":false},{"text":"Visual field exam","correct":true,"visible":false}]},{"id":3066,"text":"Which of the following is not seen in Cushing's syndrome?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 1123.","responses":[{"text":"Hyperglycemia","correct":false,"visible":false},{"text":"Weight gain","correct":false,"visible":false},{"text":"Purple striae","correct":false,"visible":false},{"text":"Weight loss","correct":true,"visible":false},{"text":"Hirsutism","correct":false,"visible":false}]},{"id":3068,"text":"What is cretinism?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Robbins SL, eds. Robbins Basic Pathology. 9th ed. Elsevier/Saunders; 2013: 1085.","responses":[{"text":"Exophthalmos","correct":false,"visible":false},{"text":"Hypoparathyroidism in children","correct":false,"visible":false},{"text":"Hypothyroidism in infancy and childhood","correct":true,"visible":false},{"text":"Hypothyroidism in adults","correct":false,"visible":false},{"text":"Hyperparathyroidism in adults","correct":false,"visible":false}]},{"id":3069,"text":"What is the correct match-up between the hormone and its percentage secretion from the adenohypophysis?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 897.","responses":[{"text":"Prolactin - 40%","correct":false,"visible":false},{"text":"Follicle stimulating hormone - 20%","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone - 40%","correct":false,"visible":false},{"text":"Growth hormone - 50%","correct":true,"visible":false},{"text":"Leutinizing hormone - 50%","correct":false,"visible":false}]},{"id":3071,"text":"An excess of mineralocorticoids will cause which of the following?","explanation":null,"reference":null,"responses":[{"text":"High blood pressure","correct":true,"visible":false},{"text":"Low blood pressure","correct":false,"visible":false},{"text":"High cortisol","correct":false,"visible":false},{"text":"Low osmolarity of blood","correct":false,"visible":false},{"text":"High growth hormone","correct":false,"visible":false}]},{"id":3072,"text":"A woman presents to the emergency with amenorrhea and milk secretion for the past 2 months. On examination, it was found that the patient has pituitary adenoma. Which of the following hormone, released by the tumor, is responsible for the patient's symptoms?","explanation":null,"reference":null,"responses":[{"text":"Luteinizing hormone (LH)","correct":false,"visible":false},{"text":"Follicle-stimulating hormone (FSH)","correct":false,"visible":false},{"text":"Prolactin","correct":true,"visible":false},{"text":"Follicle-stimulating hormone (FSH) and luteinizing hormone (LH)","correct":false,"visible":false},{"text":"Testosterone","correct":false,"visible":false}]},{"id":3073,"text":"A person known to have small cell lung carcinoma presents to the outpatient department and had developed hyponatremia. Which of the following hormone released by the carcinoma is responsible for the patient's symptoms?","explanation":null,"reference":null,"responses":[{"text":"Prolactin","correct":false,"visible":false},{"text":"Antidiuretic hormone (ADH)","correct":true,"visible":false},{"text":"Adrenocorticotropic hormone (ACTH)","correct":false,"visible":false},{"text":"Thyroxine","correct":false,"visible":false},{"text":"Luteinizing hormone (LH)","correct":false,"visible":false}]},{"id":3076,"text":"In hypopituitarism, secretion of which hormone is affected first?","explanation":null,"reference":null,"responses":[{"text":"FSH","correct":false,"visible":false},{"text":"ACTH","correct":false,"visible":false},{"text":"LH","correct":false,"visible":false},{"text":"GH","correct":true,"visible":false},{"text":"TSH","correct":false,"visible":false}]},{"id":3077,"text":"Which of the following is correct regarding chromophil cells?","explanation":null,"reference":null,"responses":[{"text":"Cells that take stain due to granules","correct":true,"visible":false},{"text":"Cells that take stain due to mitochondira","correct":false,"visible":false},{"text":"Cells that have more than two nucleus","correct":false,"visible":false},{"text":"Cell that doesn't take stain","correct":false,"visible":false},{"text":"Cells with nissl's granules","correct":false,"visible":false}]},{"id":3079,"text":"Which of the following is correct regarding the histology of the pituitary gland?","explanation":null,"reference":null,"responses":[{"text":"Thyrotropes are the most abundant cells","correct":false,"visible":false},{"text":"Somatotropes are basophilic","correct":false,"visible":false},{"text":"Corticotropes are polygonal cells with centrally placed nuclei","correct":false,"visible":false},{"text":"Pars intermedia is well developed in humans","correct":false,"visible":false},{"text":"Pars distalis makes up 75 % of the gland","correct":true,"visible":false}]},{"id":3080,"text":"Which of the following consists of stored hormones?","explanation":null,"reference":null,"responses":[{"text":"Pineal gland","correct":false,"visible":false},{"text":"Neurohypophysis","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Adenohypophysis","correct":false,"visible":false},{"text":"Hypothalamus","correct":false,"visible":false}]},{"id":3082,"text":"The floor plate of the diencephalon will give rise to which structure?","explanation":null,"reference":null,"responses":[{"text":"Pineal body","correct":false,"visible":false},{"text":"Pars nervosa","correct":true,"visible":false},{"text":"Mamillary body","correct":false,"visible":false},{"text":"Adenohypophysis","correct":false,"visible":false},{"text":"Pars intermedia","correct":false,"visible":false}]},{"id":3085,"text":"What is the correct statement regarding the structure of oxytocin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 938.","responses":[{"text":"It is an eicosanoid","correct":false,"visible":false},{"text":"It is a protein hormone of 9 amino acids","correct":true,"visible":false},{"text":"It is a steroid hormone of around 21 carbons","correct":false,"visible":false},{"text":"It is a modified amino acid of tyrosine","correct":false,"visible":false},{"text":"It is a protein hormone of 26 amino acids","correct":false,"visible":false}]},{"id":3086,"text":"Which of the following statements is incorrect regarding the hypothalamic-hypophyseal portal system?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 416.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"It arises from the superior hypophyseal artery","correct":false,"visible":false},{"text":"It arises from the inferior hypophyseal artery","correct":true,"visible":false},{"text":"Transports releasing/inhibiting factors","correct":false,"visible":false},{"text":"Capillary plexus in infundibulum","correct":false,"visible":false}]},{"id":3087,"text":"In which of the following conditions will there be decreased secretion of antidiuretic hormone (ADH)?","explanation":null,"reference":null,"responses":[{"text":"Increase angiotensin II release","correct":false,"visible":false},{"text":"Intake of less amount of water","correct":false,"visible":false},{"text":"Syndrome of inappropriate antidiuretic hormone secretion (SIADH)","correct":false,"visible":false},{"text":"Astronaut and weightlessness","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":3088,"text":"What zone(s) of the adrenal gland secrete cortisol?","explanation":null,"reference":"1) Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 424.\r\n\r\n2) Antoniou-Tsigkos A, Zapanti E, Ghizzoni L, Mastorakos G. Adrenal androgens. In: Feingold KR, Anawalt B, Boyce A, et al., eds. Endotext. MDText.com, Inc.; 2000. Accessed June 26, 2022. http://www.ncbi.nlm.nih.gov/books/NBK278929/","responses":[{"text":"Zona reticularis","correct":false,"visible":false},{"text":"Zona fasciculata and reticularis","correct":true,"visible":false},{"text":"Zona fasciculata","correct":false,"visible":false},{"text":"Zona glomerulosa","correct":false,"visible":false},{"text":"Zona pellucida","correct":false,"visible":false}]},{"id":3089,"text":"A person may get brown skin due to which of the following conditions?","explanation":null,"reference":"Moon HR, Won CH, Chang SE, Lee MW, Choi JH, Moon KC. Generalised hyperpigmentation caused by ectopic adrenocorticotropic hormone syndrome with recurrent thymic neuroendocrine carcinoma. The Australasian Journal of Dermatology.","responses":[{"text":"Increased activity of somatotrophs","correct":false,"visible":false},{"text":"Decreased melanin","correct":false,"visible":false},{"text":"Decreased activity of somatotrophs","correct":false,"visible":false},{"text":"Increased ACTH production","correct":true,"visible":false},{"text":"Decreased ACTH production","correct":false,"visible":false}]},{"id":3090,"text":"Which of the following causes a decrease in growth hormone release?","explanation":null,"reference":null,"responses":[{"text":"Exercise","correct":false,"visible":false},{"text":"Sleep","correct":false,"visible":false},{"text":"Hypoglycemia","correct":false,"visible":false},{"text":"Obesity","correct":true,"visible":false},{"text":"Stress","correct":false,"visible":false}]},{"id":3092,"text":"In which of the following conditions is IGF-1 (somatomedin C) released?","explanation":null,"reference":null,"responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Aging","correct":false,"visible":false},{"text":"Obesity","correct":false,"visible":false},{"text":"Exercise","correct":true,"visible":false},{"text":"Hyperglycemia","correct":false,"visible":false}]},{"id":3094,"text":"What is the major lifestyle risk of developing type 2 diabetes mellitus?","explanation":null,"reference":null,"responses":[{"text":"Obesity","correct":true,"visible":false},{"text":"High mental stress","correct":false,"visible":false},{"text":"Underweight","correct":false,"visible":false},{"text":"Physically active","correct":false,"visible":false},{"text":"Parenthood","correct":false,"visible":false}]},{"id":3095,"text":"Which of the following is correct regarding Sheehan syndrome?","explanation":null,"reference":null,"responses":[{"text":"Ischemic necrosis of pituitary","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Prepartum necrosis of adenohypophysis","correct":false,"visible":false},{"text":"During pregnancy posterior pituitary enlarges twice its size","correct":false,"visible":false},{"text":"Infarction of posterior lobe","correct":false,"visible":false}]},{"id":3097,"text":"Which of the following is the most common type of pituitary adenoma?","explanation":null,"reference":null,"responses":[{"text":"Prolactinoma","correct":true,"visible":false},{"text":"Growth hormone cell adenoma","correct":false,"visible":false},{"text":"FSH-producing adenoma","correct":false,"visible":false},{"text":"ACTH cell adenoma","correct":false,"visible":false},{"text":"LH-producing adenoma","correct":false,"visible":false}]},{"id":3104,"text":"Which of the following cells produce calcitonin?","explanation":"**Calcitonin** is a hormone that plays a crucial role in calcium homeostasis. It is produced and secreted by the **parafollicular cells**, also known as **C-cells**, which are specialized cells located within the thyroid gland.\r\n\r\nThe thyroid gland is primarily composed of thyroid follicles, which are spherical structures containing colloid. The thyroid follicular cells within these follicles produce and secrete the thyroid hormones, namely **thyroxine (T4)** and **triiodothyronine (T3)**.\r\n\r\nOn the other hand, the parafollicular cells are located between the thyroid follicles. These cells are responsible for synthesizing and releasing calcitonin in response to high blood calcium levels. Calcitonin acts to lower blood calcium levels by inhibiting bone resorption and enhancing calcium excretion by the kidneys.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1002.","responses":[{"text":"Chief cells","correct":false,"visible":false},{"text":"Thyroid follicular cells","correct":false,"visible":false},{"text":"Islets of Langerhans","correct":false,"visible":false},{"text":"Parafollicular cells","correct":true,"visible":false},{"text":"Chromaffin cells","correct":false,"visible":false}]},{"id":3111,"text":"The principle target of aldosterone is which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 352.","responses":[{"text":"Carotid sinus","correct":false,"visible":false},{"text":"Mesangial cells","correct":false,"visible":false},{"text":"Vascular endothelium","correct":false,"visible":false},{"text":"Principal cells of the nephron","correct":true,"visible":false},{"text":"All of these","correct":false,"visible":false}]},{"id":3112,"text":"Which of the following is the most common disease of the thyroid in mountainous areas?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1083.","responses":[{"text":"Myxedema","correct":false,"visible":false},{"text":"Endemic goiter","correct":true,"visible":false},{"text":"Hashimoto's thyroiditis","correct":false,"visible":false},{"text":"Graves disease","correct":false,"visible":false},{"text":"Iatrogenic goiter","correct":false,"visible":false}]},{"id":3115,"text":"Cholesterol is the precursor for all lipid-soluble hormones except which of the following?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 237.","responses":[{"text":"Estrogen","correct":false,"visible":false},{"text":"Glucocorticoid","correct":false,"visible":false},{"text":"Retinoic acid","correct":true,"visible":false},{"text":"Progesterone","correct":false,"visible":false},{"text":"Testosterone","correct":false,"visible":false}]},{"id":3116,"text":"Which of the following is not present above the pituitary gland?","explanation":null,"reference":null,"responses":[{"text":"Hypothalamus","correct":false,"visible":false},{"text":"Corpus callosum","correct":false,"visible":false},{"text":"Optic chiasma","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Sphenoidal sinus","correct":true,"visible":false}]},{"id":3117,"text":"Which of the following hormone is released by two glands?","explanation":null,"reference":null,"responses":[{"text":"Antidiuretic hormone","correct":false,"visible":false},{"text":"Oxytocin","correct":false,"visible":false},{"text":"Somatostatin","correct":true,"visible":false},{"text":"Follicle stimulating hormone","correct":false,"visible":false},{"text":"Prolactin","correct":false,"visible":false}]},{"id":3118,"text":"Genetic abnormalities are associated with pituitary adenomas. Which of the following is the most common genetic abnormality in pituitary adenomas?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1068.","responses":[{"text":"cAMP formation mutation","correct":false,"visible":false},{"text":"Defect in retinoblastoma","correct":false,"visible":false},{"text":"GDP formation mutation","correct":false,"visible":false},{"text":"G-protein mutation","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":3119,"text":"Which of the following hormones are linked with increased bone resorption?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1117.","responses":[{"text":"Cortisol","correct":true,"visible":false},{"text":"Growth hormone","correct":false,"visible":false},{"text":"Melatonin","correct":false,"visible":false},{"text":"Thyroid hormone","correct":false,"visible":false},{"text":"Aldosterone","correct":false,"visible":false}]},{"id":3122,"text":"Which of the following greatly increases aldosterone secretion?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 961.","responses":[{"text":"Increased Cl- ion concentration in extracellular fluid","correct":false,"visible":false},{"text":"Increased K+ ion concentration in extracellular fluid","correct":true,"visible":false},{"text":"Decreased activity of renin-angiotensin system","correct":false,"visible":false},{"text":"ACTH from anterior pituitary gland","correct":false,"visible":false},{"text":"Increased Na+ ion concentration in extracellular fluid","correct":false,"visible":false}]},{"id":3129,"text":"Which of the following is incorrect about growth hormone (GH)?","explanation":null,"reference":null,"responses":[{"text":"GH release is increased in exercise","correct":false,"visible":false},{"text":"IGF-1 causes release of GH","correct":true,"visible":false},{"text":"GH stimulates the release of IGF-1","correct":false,"visible":false},{"text":"Somatostatin inhibits GH","correct":false,"visible":false},{"text":"GH is released in pulses","correct":false,"visible":false}]},{"id":3130,"text":"Which of the following is correct about chromophobe cells?","explanation":null,"reference":null,"responses":[{"text":"Are similar as chromophil cells","correct":false,"visible":false},{"text":"Stain due to nissl granules","correct":false,"visible":false},{"text":"Stain darkly due to granules","correct":false,"visible":false},{"text":"Stain weakly under light microscope","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":3131,"text":"Which of the following hormones have the same alpha unit?","explanation":null,"reference":null,"responses":[{"text":"TSH, LH, FSH","correct":true,"visible":false},{"text":"GH, prolactin, LH","correct":false,"visible":false},{"text":"LH, TSH","correct":false,"visible":false},{"text":"ACTH, TSH","correct":false,"visible":false},{"text":"TSH, GH","correct":false,"visible":false}]},{"id":3132,"text":"Growth hormone is inhibited by which of the following?","explanation":null,"reference":null,"responses":[{"text":"Exercise","correct":false,"visible":false},{"text":"Hypoglycemia","correct":false,"visible":false},{"text":"Somatomedin","correct":true,"visible":false},{"text":"Deep sleep","correct":false,"visible":false},{"text":"Gonadotropin-releasing hormone (GnRH)","correct":false,"visible":false}]},{"id":3133,"text":"Exogenous administration of which of the following substances will decrease the release of growth hormone?","explanation":null,"reference":null,"responses":[{"text":"Alpha adrenergic agonists","correct":false,"visible":false},{"text":"Ganglion blockers","correct":false,"visible":false},{"text":"5-HT receptor agonist","correct":false,"visible":false},{"text":"Dopamine","correct":true,"visible":false},{"text":"Beta adrenergic agonist","correct":false,"visible":false}]},{"id":3134,"text":"Somatomedins act as which of the following?","explanation":null,"reference":null,"responses":[{"text":"Inhibitors","correct":false,"visible":false},{"text":"Antagonist","correct":false,"visible":false},{"text":"Partial agonist","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Stimulators","correct":true,"visible":false}]},{"id":3135,"text":"Which of the following is not an indication for vasopressin therapy?","explanation":null,"reference":null,"responses":[{"text":"Von Willebrand disease","correct":false,"visible":false},{"text":"Esophageal varices","correct":false,"visible":false},{"text":"Venous thromboembolism","correct":true,"visible":false},{"text":"Diverticular bleeding","correct":false,"visible":false},{"text":"Diabetes Insipidus","correct":false,"visible":false}]},{"id":3136,"text":"What is another name of the anterior pituitary gland?","explanation":null,"reference":null,"responses":[{"text":"Pars nervosa","correct":false,"visible":false},{"text":"Pars intermedia","correct":false,"visible":false},{"text":"All of them","correct":false,"visible":false},{"text":"Neurohypophysis","correct":false,"visible":false},{"text":"Adenohypophysis","correct":true,"visible":false}]},{"id":3137,"text":"Which of the following drug is used to treat acromegaly?","explanation":null,"reference":null,"responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Metformin","correct":false,"visible":false},{"text":"Octreotide and pegvisomant","correct":true,"visible":false},{"text":"Regular insulin","correct":false,"visible":false},{"text":"Desmopressin","correct":false,"visible":false}]},{"id":3138,"text":"A 40-year-old man comes to the OPD complaining of muscle weakness. He is 6 feet tall and has a protruding lower jaw, along with enlarged hands and feet. What is your diagnosis of the patient and what will you expect his lab tests to reveal?","explanation":null,"reference":null,"responses":[{"text":"Acromegaly, with increased GH and IGF-1","correct":true,"visible":false},{"text":"Gigantism, with increased GH and IGF-1","correct":false,"visible":false},{"text":"Hypopituitarism, with increased GH","correct":false,"visible":false},{"text":"Hashitoxicosis, with increased T3 and T4, and low TSH","correct":false,"visible":false},{"text":"Cushing syndrome, with increased midnight plasma cortisol","correct":false,"visible":false}]},{"id":3139,"text":"Somatotrophs release which of the following hormone?","explanation":null,"reference":null,"responses":[{"text":"Growth hormone","correct":true,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Melanocyte-stimulating hormone (MSH)","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone (ACTH)","correct":false,"visible":false},{"text":"Oxytocin","correct":false,"visible":false},{"text":"Thyroid-stimulating hormone (TSH)","correct":false,"visible":false}]},{"id":3140,"text":"In which of the following conditions is human growth hormone given?","explanation":null,"reference":null,"responses":[{"text":"Hyperpituitarism","correct":false,"visible":false},{"text":"All of them","correct":false,"visible":false},{"text":"Gigantism","correct":false,"visible":false},{"text":"Panhypopituitarism","correct":true,"visible":false},{"text":"Acromegaly","correct":false,"visible":false}]},{"id":3141,"text":"Which of the following does not occur in panhypopituitarism?","explanation":null,"reference":null,"responses":[{"text":"Hypogonadism","correct":false,"visible":false},{"text":"Mental retardation","correct":false,"visible":false},{"text":"Reduced growth","correct":false,"visible":false},{"text":"None of them","correct":true,"visible":false},{"text":"Reduced thyroxine","correct":false,"visible":false}]},{"id":3142,"text":"Growth hormone-releasing hormone (GHRH) is released from which structure?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 932.","responses":[{"text":"Pancreas","correct":false,"visible":false},{"text":"Adrenal gland","correct":false,"visible":false},{"text":"Hypothalamus","correct":true,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Pituitary gland","correct":false,"visible":false}]},{"id":3143,"text":"Which of the following statements is incorrect regarding vasopressin?","explanation":null,"reference":null,"responses":[{"text":"Used in the treatment of diabetes insipidus","correct":false,"visible":false},{"text":"Used to control variceal bleeding","correct":false,"visible":false},{"text":"Promote diuresis","correct":true,"visible":false},{"text":"Prevent side effects during abdominal X-ray","correct":false,"visible":false},{"text":"Help to increase blood pressure","correct":false,"visible":false}]},{"id":3144,"text":"Deficiency of which hormone causes fatty liver?","explanation":null,"reference":null,"responses":[{"text":"Oxytocin","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Somatostatin","correct":false,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"Growth hormone","correct":true,"visible":false}]},{"id":3145,"text":"Which of the following is not associated with acromegaly?","explanation":null,"reference":null,"responses":[{"text":"Frontal bossing","correct":false,"visible":false},{"text":"Insulin resistance","correct":false,"visible":false},{"text":"Hypertension","correct":false,"visible":false},{"text":"Large tongue and hands","correct":false,"visible":false},{"text":"Mental deficit","correct":true,"visible":false}]},{"id":3146,"text":"Regarding the pituitary gland, which is false?","explanation":null,"reference":null,"responses":[{"text":"It lies in the ethmoid cavity","correct":true,"visible":false},{"text":"Is adjacent to the optic chiasma","correct":false,"visible":false},{"text":"It is covered superiorly by the diaphragma sella","correct":false,"visible":false},{"text":"It is seated in the sella turcica","correct":false,"visible":false},{"text":"It is located under the diencephalon","correct":false,"visible":false}]},{"id":3147,"text":"Growth retardation occurs due to deficiency of which hormone?","explanation":null,"reference":null,"responses":[{"text":"Follicle stimulating hormone","correct":false,"visible":false},{"text":"Growth hormone","correct":true,"visible":false},{"text":"Adrenocorticotropic hormone","correct":false,"visible":false},{"text":"Prolactin","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":3148,"text":"What are the main clinical features of a prolactinoma?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 159.","responses":[{"text":"Acne and weight gain","correct":false,"visible":false},{"text":"Acromegaly, hyperostosis, and prognathism","correct":false,"visible":false},{"text":"Galactorrhea, amenorrhea, and infertility","correct":true,"visible":false},{"text":"Vision disturbance, headaches, and mood swings","correct":false,"visible":false},{"text":"Hyperpigmentation and decreased libido","correct":false,"visible":false}]},{"id":3149,"text":"With the help of which hormone does thyrotropin-releasing hormone cause secretion of thyroxine?","explanation":null,"reference":null,"responses":[{"text":"Thyroid stimulating hormone","correct":true,"visible":false},{"text":"Antidiuretic hormone","correct":false,"visible":false},{"text":"Follicle stimulating hormone","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false},{"text":"Adrenaline","correct":false,"visible":false}]},{"id":3154,"text":"Insulin is a polypeptide. Which of the following statement is correct about insulin?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 313.","responses":[{"text":"It is usually given orally","correct":false,"visible":false},{"text":"It stimulates the release of glycogen","correct":false,"visible":false},{"text":"It stimulates the release of bile","correct":false,"visible":false},{"text":"It is destroyed by gastric enzymes","correct":true,"visible":false},{"text":"It increases gluconeogenesis","correct":false,"visible":false}]},{"id":3158,"text":"Oxyphil and principal cells are found in the parathyroid gland. Which of the following is a feature of oxyphil cells?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 434.","responses":[{"text":"They have a basophilic cytoplasm","correct":false,"visible":false},{"text":"They are arranged in small clusters","correct":true,"visible":false},{"text":"They give rise to principal cells","correct":false,"visible":false},{"text":"They are smaller than principal cells","correct":false,"visible":false},{"text":"Their number decreases with age","correct":false,"visible":false}]},{"id":3159,"text":"Which of the following is the confirmation test for Addison's disease?","explanation":null,"reference":"Munir S, Quintanilla Rodriguez BS, Waseem M. Addison disease. In: StatPearls. StatPearls Publishing; 2022. Accessed June 27, 2022. http://www.ncbi.nlm.nih.gov/books/NBK4419","responses":[{"text":"Glucose levels","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone levels","correct":false,"visible":false},{"text":"Cortisol levels","correct":false,"visible":false},{"text":"Aldosterone levels","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone stimulation test","correct":true,"visible":false}]},{"id":3163,"text":"Which of the following changes in thyroid profile are seen in pregnancy?","explanation":null,"reference":null,"responses":[{"text":"Low free T3 and T4","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"High total T4 and normal TSH","correct":true,"visible":false},{"text":"High free T3 and T4","correct":false,"visible":false},{"text":"Low total T3 and T4","correct":false,"visible":false}]},{"id":3164,"text":"Exercise stimulates the release of which of the following hormones?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 933.","responses":[{"text":"Growth hormone","correct":true,"visible":false},{"text":"Parathyroid hormone","correct":false,"visible":false},{"text":"Thyroxine","correct":false,"visible":false},{"text":"Progesterone","correct":false,"visible":false},{"text":"Insulin","correct":false,"visible":false}]},{"id":3165,"text":"Which of the following steps of thyroid hormone synthesis are impaired due to thyroid peroxidase enzyme deficiency?","explanation":null,"reference":null,"responses":[{"text":"Reduction and oxidation","correct":false,"visible":false},{"text":"Binding of iodide to thyroglobulin","correct":false,"visible":false},{"text":"Coupling only","correct":false,"visible":false},{"text":"Absorption of iodine","correct":false,"visible":false},{"text":"Oxidation, organification \u0026 coupling","correct":true,"visible":false}]},{"id":3166,"text":"Thyroid storm is seen in which of the following diseases?","explanation":null,"reference":null,"responses":[{"text":"Wolff-Chaikoff effect","correct":false,"visible":false},{"text":"Myxedema coma","correct":false,"visible":false},{"text":"Hashimoto’s thyroiditis","correct":false,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Grave’s disease","correct":true,"visible":false}]},{"id":3167,"text":"Which of the following statement is correct regarding the isthmus of the thyroid gland?","explanation":null,"reference":null,"responses":[{"text":"Lies directly anterior to the thyroid cartilage","correct":false,"visible":false},{"text":"Contains the superior pair of parathyroid glands","correct":false,"visible":false},{"text":"Is the same as the pyramidal lobe","correct":false,"visible":false},{"text":"Lies directly anterior to the 2nd, 3rd, and 4th tracheal rings","correct":true,"visible":false},{"text":"Lies directly anterior to the cricoid cartilage","correct":false,"visible":false}]},{"id":3172,"text":"Graves disease is an example of which type of hypersensitivity?","explanation":null,"reference":null,"responses":[{"text":"Type II","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Type III","correct":false,"visible":false},{"text":"Type I","correct":false,"visible":false},{"text":"Type IV","correct":false,"visible":false}]},{"id":3175,"text":"Which of the following is the most obvious clinical manifestation of long-standing iodine deficiency?","explanation":null,"reference":null,"responses":[{"text":"Reproductive failure","correct":false,"visible":false},{"text":"Mental retardation","correct":false,"visible":false},{"text":"Endemic cretinism","correct":false,"visible":false},{"text":"Abortion","correct":false,"visible":false},{"text":"Goiter","correct":true,"visible":false}]},{"id":3180,"text":"Which of the following is not seen in hypopituitarism?","explanation":null,"reference":null,"responses":[{"text":"Dwarfism","correct":false,"visible":false},{"text":"Decreased libido","correct":false,"visible":false},{"text":"Cachexia","correct":true,"visible":false},{"text":"Pallor","correct":false,"visible":false},{"text":"Amenorrhea","correct":false,"visible":false}]},{"id":3181,"text":"Which of the following is correct regarding the location of the lateral lobe of the thyroid gland?","explanation":null,"reference":null,"responses":[{"text":"Extends from the oblique line of thyroid cartilage to 4th tracheal ring","correct":false,"visible":false},{"text":"Extends from the oblique line of thyroid cartilage to 1st tracheal ring","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Extends from the oblique line of thyroid cartilage to 5th or 6th tracheal ring","correct":true,"visible":false},{"text":"Extends from the oblique line of thyroid cartilage to 3rd tracheal ring","correct":false,"visible":false}]},{"id":3184,"text":"How to differentiate between type 1 and type 2 diabetes mellitus?","explanation":null,"reference":null,"responses":[{"text":"None of them","correct":false,"visible":false},{"text":"By the presence of peptide c","correct":true,"visible":false},{"text":"By the presence of glucagon","correct":false,"visible":false},{"text":"By the presence of somatostatin","correct":false,"visible":false},{"text":"By the presence of receptor","correct":false,"visible":false}]},{"id":3185,"text":"One of the reasons for gigantism is the oversecretion of which of the following hormone?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1071.","responses":[{"text":"Prolactin","correct":false,"visible":false},{"text":"Corticotropin","correct":false,"visible":false},{"text":"Thyrotropin","correct":false,"visible":false},{"text":"Gonadotropin","correct":false,"visible":false},{"text":"Somatotropin","correct":true,"visible":false}]},{"id":3190,"text":"Which of the following regulates mineralocorticoids?","explanation":null,"reference":null,"responses":[{"text":"Thyroid-stimulating hormone","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Thyrotropin-releasing hormone","correct":false,"visible":false},{"text":"Angiotensin II","correct":true,"visible":false}]},{"id":3193,"text":"Which of the following is true about calcium transport in plasma?","explanation":null,"reference":null,"responses":[{"text":"Ionized Ca+ is the biologically inactive form","correct":false,"visible":false},{"text":"50% is in ionized from","correct":true,"visible":false},{"text":"20% is complexed to phosphate and citrate","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"30% is bound to plasma proteins","correct":false,"visible":false}]},{"id":3194,"text":"Which of the following are neural crest cells of adrenal medulla derived from?","explanation":null,"reference":null,"responses":[{"text":"Sympathetic ganglia","correct":true,"visible":false},{"text":"Parasympathetic ganglia","correct":false,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"Dorsal ganglia","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":3195,"text":"Which of the following is true regarding the development of the thyroid gland?","explanation":null,"reference":null,"responses":[{"text":"All of these","correct":false,"visible":false},{"text":"It originates as a diverticulum between the 3rd and 4th pharyngeal pouches","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"It starts from the foramen cecum","correct":true,"visible":false},{"text":"It is the body's second endocrine gland to develop","correct":false,"visible":false}]},{"id":3196,"text":"Which of the following is the most common parathyroid tumor?","explanation":null,"reference":null,"responses":[{"text":"Multiple endocrine neoplasia type 1","correct":false,"visible":false},{"text":"Parathyroid hyperplasia","correct":false,"visible":false},{"text":"Parathyroid carcinoma","correct":false,"visible":false},{"text":"Parathyroid adenoma","correct":true,"visible":false},{"text":"Multiple endocrine neoplasia type 2","correct":false,"visible":false}]},{"id":3198,"text":"Which of the following causes muscle weakness in Conn's syndrome?","explanation":null,"reference":null,"responses":[{"text":"Hyperkalemia","correct":false,"visible":false},{"text":"Acidosis","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Hypokalemia","correct":true,"visible":false},{"text":"Hyponatremia","correct":false,"visible":false}]},{"id":3199,"text":"Which of the following drugs are used to treat hypertension in metabolic syndrome?","explanation":null,"reference":null,"responses":[{"text":"Quinolones","correct":false,"visible":false},{"text":"Corticosteroids","correct":false,"visible":false},{"text":"ACE-inhibitors","correct":true,"visible":false},{"text":"Aminoglycosides","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":3205,"text":"Which of the following is not a microvascular complication of long-standing diabetes?","explanation":null,"reference":null,"responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Diabetic neuropathy","correct":false,"visible":false},{"text":"Retinopathy","correct":false,"visible":false},{"text":"Diabetic nephropathy","correct":false,"visible":false},{"text":"Myocardial infarction","correct":true,"visible":false}]},{"id":3207,"text":"What is the effect of aldosterone on sweat glands and salivary glands?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 960.","responses":[{"text":"Releasing NaCl only","correct":false,"visible":false},{"text":"Absorbing K and releasing NaCl out of the cell","correct":false,"visible":false},{"text":"Absorbing NaCl only","correct":false,"visible":false},{"text":"Absorbing NaCl and releasing K out of the cell","correct":true,"visible":false},{"text":"Absorbing K only","correct":false,"visible":false}]},{"id":3208,"text":"Which of the following is the long-acting glucocorticoid?","explanation":null,"reference":null,"responses":[{"text":"Prednisone","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Dexamethasone","correct":true,"visible":false},{"text":"Hydrocortisone","correct":false,"visible":false},{"text":"Methyl prednisone","correct":false,"visible":false}]},{"id":3210,"text":"Regarding the adrenal cortex, which one of the following is not correct?","explanation":null,"reference":null,"responses":[{"text":"Produces steroid","correct":false,"visible":false},{"text":"Derived from neural crest","correct":true,"visible":false},{"text":"Contains lipid droplets","correct":false,"visible":false},{"text":"Derived from mesoderm","correct":false,"visible":false},{"text":"Contains SER","correct":false,"visible":false}]},{"id":3211,"text":"Which layer of the adrenal cortex is responsible for secreting aldosterone?","explanation":null,"reference":null,"responses":[{"text":"None of them","correct":false,"visible":false},{"text":"All of them","correct":false,"visible":false},{"text":"Zona fasciculata","correct":false,"visible":false},{"text":"Zona reticularis","correct":false,"visible":false},{"text":"Zona glomerulosa","correct":true,"visible":false}]},{"id":3212,"text":"Which of the following structure lies anterior to the right adrenal gland?","explanation":null,"reference":null,"responses":[{"text":"Spleen","correct":false,"visible":false},{"text":"Liver","correct":true,"visible":false},{"text":"Kidney","correct":false,"visible":false},{"text":"Pancreas","correct":false,"visible":false},{"text":"Splenic artery","correct":false,"visible":false}]},{"id":3214,"text":"Thyroiditis is the inflammation of the thyroid gland encompassing a number of disorders that have some elements of inflammation. Subacute thyroiditis is believed to be triggered by which of the following insults?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 163.","responses":[{"text":"Viral infection","correct":true,"visible":false},{"text":"Iodine deficiency","correct":false,"visible":false},{"text":"Bacterial infection","correct":false,"visible":false},{"text":"Trauma","correct":false,"visible":false},{"text":"Fungal infection","correct":false,"visible":false}]},{"id":3215,"text":"A 45-year-old patient has been prescribed the 4-drug anti-tuberculous regimen for the next 3 months following a diagnosis of pulmonary tuberculosis. However, a few days later it is reported that the patient expired. What underlying undiagnosed condition most likely resulted in the demise of this patient?","explanation":null,"reference":null,"responses":[{"text":"Congenital adrenal hyperplasia","correct":false,"visible":false},{"text":"Addison's disease","correct":true,"visible":false},{"text":"Hyperaldosteronism","correct":false,"visible":false},{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Hypoaldosteronism","correct":false,"visible":false}]},{"id":3219,"text":"What is the most common cause of congenital hypothyroidism in iodine sufficient regions?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1077.","responses":[{"text":"Deficiency of thyroid stimulating hormone","correct":false,"visible":false},{"text":"Drugs during pregnancy","correct":false,"visible":false},{"text":"Poor feeding","correct":false,"visible":false},{"text":"Dyshormonogenetic goiter","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":3221,"text":"Which of the following is the cause of central hypothyroidism?","explanation":null,"reference":null,"responses":[{"text":"Defect in thyroid gland","correct":false,"visible":false},{"text":"Decreased free T3","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Decreased T4","correct":false,"visible":false},{"text":"Insufficient stimulation by TSH","correct":true,"visible":false}]},{"id":3223,"text":"Which of the following will increase thyroid hormone secretion?","explanation":null,"reference":null,"responses":[{"text":"Exercise","correct":true,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Low thyroid stimulating hormone","correct":false,"visible":false},{"text":"Thyroid agenesis","correct":false,"visible":false}]},{"id":3225,"text":"Which of the following conditions causes hyperthyroidism?","explanation":null,"reference":null,"responses":[{"text":"All of them","correct":false,"visible":false},{"text":"Congenital hypothyroidism","correct":false,"visible":false},{"text":"Hashimoto thyroiditis","correct":false,"visible":false},{"text":"Graves disease","correct":true,"visible":false},{"text":"Iodine deficiency","correct":false,"visible":false}]},{"id":3226,"text":"Which of the following is the very first test to be done for hypothyroidism?","explanation":null,"reference":null,"responses":[{"text":"Total T4 and T3","correct":false,"visible":false},{"text":"TSH","correct":true,"visible":false},{"text":"Free T3","correct":false,"visible":false},{"text":"T3","correct":false,"visible":false},{"text":"T4","correct":false,"visible":false}]},{"id":3228,"text":"Iodine uptake is through:","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 941.","responses":[{"text":"Present within the cell","correct":false,"visible":false},{"text":"Apical membrane","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Lateral membrane","correct":false,"visible":false},{"text":"Basal membrane","correct":true,"visible":false}]},{"id":3229,"text":"Radioactive iodine uptake is used for which of the following?","explanation":null,"reference":null,"responses":[{"text":"Diagnosis and treatment for thyroid disorders","correct":true,"visible":false},{"text":"Checking presence of drug","correct":false,"visible":false},{"text":"Treatment of thyroid disorders only","correct":false,"visible":false},{"text":"Diagnosis of thyroid disorders only","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":3230,"text":"Hyperparathyroidism leads to a decrease in plasma levels of which of these?","explanation":"Hyperparathyroidism leads to an increase in plasma levels of calcium (hypercalcemia) and a decrease in plasma levels of **phosphate** (hypophosphatemia).\r\n\r\nIn hyperparathyroidism, the excessive secretion of parathyroid hormone (PTH) from the parathyroid glands causes increased reabsorption of calcium from bones, increased absorption of calcium from the intestines, and decreased excretion of calcium by the kidneys. As a result, the calcium levels in the blood rise.\r\n\r\nAt the same time, PTH also affects the handling of phosphate in the kidneys, leading to increased excretion of phosphate in the urine. This results in a decrease in plasma levels of phosphate.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 165.","responses":[{"text":"Sodium","correct":false,"visible":false},{"text":"Potassium","correct":false,"visible":false},{"text":"Calcitonin","correct":false,"visible":false},{"text":"Phosphate","correct":true,"visible":false},{"text":"Calcium","correct":false,"visible":false}]},{"id":3231,"text":"A 34-year-old female comes to the outpatient department with uncontrolled hypertension. A computed tomography (CT) scan reveals bilateral enlargement of the suprarenal gland. What is the most probable cause?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1127-1128.","responses":[{"text":"Renal cyst","correct":false,"visible":false},{"text":"Renal tumor","correct":false,"visible":false},{"text":"Pheochromocytoma","correct":true,"visible":false},{"text":"Hyperplasia of suprarenal cortex","correct":false,"visible":false},{"text":"Hyperplasia of suprarenal medulla","correct":false,"visible":false}]},{"id":3233,"text":"Which of the following stimulates growth hormone secretion?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 933.","responses":[{"text":"Increased blood glucose","correct":false,"visible":false},{"text":"Somatomedins","correct":false,"visible":false},{"text":"Deep sleep","correct":true,"visible":false},{"text":"Increased free fatty acid level in blood","correct":false,"visible":false},{"text":"Aging","correct":false,"visible":false}]},{"id":3237,"text":"A 1-year-old boy is brought to the outpatient department with an abnormal opening along the anterior border of the sternocleidomastoid muscle in the inferior third of the neck and discharge of mucus from it is observed. Which of the following is the most likely diagnosis?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 164.","responses":[{"text":"Cervical sinus","correct":true,"visible":false},{"text":"Cervical cyst","correct":false,"visible":false},{"text":"Cervical vestiges","correct":false,"visible":false},{"text":"Piriform sinus fistula","correct":false,"visible":false},{"text":"DiGeorge syndrome","correct":false,"visible":false}]},{"id":3241,"text":"The adrenal cortex is developmentally derived from which of the following?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 75.","responses":[{"text":"Surface ectoderm","correct":false,"visible":false},{"text":"Epiblast cell","correct":false,"visible":false},{"text":"Neural crest cell","correct":false,"visible":false},{"text":"Mesoderm","correct":true,"visible":false},{"text":"Endoderm","correct":false,"visible":false}]},{"id":3245,"text":"Which of the following is used to check catecholamine degradation?","explanation":null,"reference":null,"responses":[{"text":"Vanillylmandelic acid in urine","correct":true,"visible":false},{"text":"Glucose tolerance test","correct":false,"visible":false},{"text":"Complete blood count","correct":false,"visible":false},{"text":"Lactate threshold test","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":3254,"text":"Which of the following is the principal glucocorticoid in the body?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 955.","responses":[{"text":"Deoxymethasone","correct":false,"visible":false},{"text":"Corticosterone","correct":false,"visible":false},{"text":"Cortisol","correct":true,"visible":false},{"text":"Aspirin","correct":false,"visible":false},{"text":"Aldosterone","correct":false,"visible":false}]},{"id":3255,"text":"During a histological examination, a student observes a slide showing a group of secretory cells with fenestrated capillaries. On further examination, cells appear to be of four different types. The slide is taken from which of the following?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 427.","responses":[{"text":"Tail of pancreas","correct":true,"visible":false},{"text":"Follicles of thyroid","correct":false,"visible":false},{"text":"Sinusoids of liver","correct":false,"visible":false},{"text":"Head of pancreas","correct":false,"visible":false},{"text":"Medulla of adrenal gland","correct":false,"visible":false}]},{"id":3256,"text":"Which of the following is the obligatory and intermediate lipophilic and hydrophobic hormone in the biosynthesis of both estradiol and dihydrotestosterone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 1033.","responses":[{"text":"Cholesterol","correct":false,"visible":false},{"text":"Testosterone","correct":false,"visible":false},{"text":"Estrogen","correct":false,"visible":false},{"text":"Pregnenolone","correct":true,"visible":false},{"text":"Progesterone","correct":false,"visible":false}]},{"id":3257,"text":"Hyperthyroidism causes a decrease in:","explanation":null,"reference":null,"responses":[{"text":"Metabolic rate","correct":false,"visible":false},{"text":"Cholesterol and phospholipids","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Temperature","correct":false,"visible":false},{"text":"Sweating","correct":false,"visible":false}]},{"id":3260,"text":"Which of the following is wrong about radioactive iodine?","explanation":null,"reference":null,"responses":[{"text":"It is given intravenously","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"It is given orally","correct":false,"visible":false},{"text":"Used for diagnosis","correct":false,"visible":false},{"text":"It is a single dose","correct":false,"visible":false}]},{"id":3266,"text":"What are the side effects of levothyroxine?","explanation":null,"reference":null,"responses":[{"text":"Nephropathy","correct":false,"visible":false},{"text":"Vision loss","correct":false,"visible":false},{"text":"Tachycardia","correct":true,"visible":false},{"text":"Myocardial infarction","correct":false,"visible":false},{"text":"Neuropathy","correct":false,"visible":false}]},{"id":3268,"text":"A patient presented to the clinic with the symptoms of hyperthyroidism. Which of the following should be assessed to confirm the diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1077.","responses":[{"text":"Thyroglobulin","correct":false,"visible":false},{"text":"TRH","correct":false,"visible":false},{"text":"TSH","correct":true,"visible":false},{"text":"Free T3","correct":false,"visible":false},{"text":"T4","correct":false,"visible":false}]},{"id":3271,"text":"Hurthle cells show:","explanation":null,"reference":null,"responses":[{"text":"Atrophy","correct":false,"visible":false},{"text":"Dysplasia","correct":false,"visible":false},{"text":"Metaplastic change","correct":true,"visible":false},{"text":"Hyperplasia","correct":false,"visible":false},{"text":"Hypertrophy","correct":false,"visible":false}]},{"id":3272,"text":"Hashimoto thyroiditis can lead to:","explanation":null,"reference":null,"responses":[{"text":"All of them","correct":false,"visible":false},{"text":"Thyroid lymphoma","correct":true,"visible":false},{"text":"Pancytopenia","correct":false,"visible":false},{"text":"Pretibial myxedema","correct":false,"visible":false},{"text":"Leukemia","correct":false,"visible":false}]},{"id":3275,"text":"Juxtaglomerular cells secrete renin in response to all of the following except:","explanation":null,"reference":null,"responses":[{"text":"Decreased blood volume","correct":false,"visible":false},{"text":"Hemorrhage","correct":false,"visible":false},{"text":"Increased heart rate","correct":true,"visible":false},{"text":"Dehydration","correct":false,"visible":false},{"text":"Decreased blood pressure","correct":false,"visible":false}]},{"id":3276,"text":"Which of the following is the best indicator for metabolic syndrome?","explanation":null,"reference":null,"responses":[{"text":"Waist circumference","correct":true,"visible":false},{"text":"Body weight","correct":false,"visible":false},{"text":"Waist hip ratio","correct":false,"visible":false},{"text":"Body mass index","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":3281,"text":"The adrenal medulla is embryologically derived from which of the following?","explanation":null,"reference":"Sadler TW. Langman’s Medical Embryology. 14th ed. Wolters Kluwer; 2018: 78.","responses":[{"text":"Epiblast","correct":false,"visible":false},{"text":"Endoderm","correct":false,"visible":false},{"text":"Surface ectoderm","correct":false,"visible":false},{"text":"Neural crest cell","correct":true,"visible":false},{"text":"Mesoderm","correct":false,"visible":false}]},{"id":3283,"text":"Cretinism is due to:","explanation":null,"reference":null,"responses":[{"text":"Hypothyroidism during fetal life, infancy \u0026 childhood","correct":true,"visible":false},{"text":"Hyperparathyroidism during adult life","correct":false,"visible":false},{"text":"Hyperthyroidism during childhood","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Increased growth hormone","correct":false,"visible":false}]},{"id":3284,"text":"What is the most common cause of iodine deficiency in Pakistan?","explanation":null,"reference":null,"responses":[{"text":"Impaired iodine absorption","correct":false,"visible":false},{"text":"Too much usage of iodine in the body","correct":false,"visible":false},{"text":"Insufficient iodine intake","correct":true,"visible":false},{"text":"Impaired iodine uptake","correct":false,"visible":false},{"text":"Hereditary","correct":false,"visible":false}]},{"id":3289,"text":"The superior parathyroid gland develops from which pharyngeal pouch?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 163.","responses":[{"text":"2nd","correct":false,"visible":false},{"text":"3rd","correct":false,"visible":false},{"text":"1st","correct":false,"visible":false},{"text":"4th","correct":true,"visible":false},{"text":"5th","correct":false,"visible":false}]},{"id":3290,"text":"Which of the following results in the formation of the pancreas?","explanation":null,"reference":null,"responses":[{"text":"Fusion of ventral and dorsal pancreatic buds","correct":true,"visible":false},{"text":"Fusion of two ventral pancreatic buds","correct":false,"visible":false},{"text":"Fusion of two dorsal pancreatic buds","correct":false,"visible":false},{"text":"Fusion of somites","correct":false,"visible":false},{"text":"Fusion of midgut and foregut buds","correct":false,"visible":false}]},{"id":3291,"text":"Which of these hormones has effects similar to cortisol?","explanation":null,"reference":null,"responses":[{"text":"Prolactin","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false},{"text":"Epinephrine","correct":true,"visible":false},{"text":"Insulin","correct":false,"visible":false}]},{"id":3292,"text":"The inferior thyroid artery is a branch of which of the following?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 1008.","responses":[{"text":"Arch of aorta","correct":false,"visible":false},{"text":"Internal thoracic trunk","correct":false,"visible":false},{"text":"Internal carotid artery","correct":false,"visible":false},{"text":"Thyro-cervical trunk","correct":true,"visible":false},{"text":"Superior thyroid artery","correct":false,"visible":false}]},{"id":3293,"text":"Which one of the following is a mediator in stress?","explanation":null,"reference":null,"responses":[{"text":"Interleukin 3","correct":false,"visible":false},{"text":"Interleukin 4","correct":false,"visible":false},{"text":"Interleukin 1","correct":true,"visible":false},{"text":"Interleukin 2","correct":false,"visible":false},{"text":"Interferon gamma (IFNγ)","correct":false,"visible":false}]},{"id":3294,"text":"What does highly excessive iodine cause?","explanation":null,"reference":null,"responses":[{"text":"Cushing syndrome","correct":false,"visible":false},{"text":"Exophthalmos","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false},{"text":"Hypothyroidism","correct":true,"visible":false}]},{"id":3297,"text":"What ions are necessary for the release of catecholamines?","explanation":null,"reference":null,"responses":[{"text":"Ca2+","correct":true,"visible":false},{"text":"Mg2+","correct":false,"visible":false},{"text":"Na+","correct":false,"visible":false},{"text":"Both Na+ and K","correct":false,"visible":false},{"text":"K+","correct":false,"visible":false}]},{"id":3300,"text":"Chvostek sign is seen in which of the following?","explanation":null,"reference":null,"responses":[{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false},{"text":"Hypercalcemia","correct":false,"visible":false},{"text":"Hypoparathyroidism","correct":true,"visible":false},{"text":"Both hyperthyroidism and hypothyroidism","correct":false,"visible":false}]},{"id":3301,"text":"Which class of diabetes drug causes peripheral edema?","explanation":null,"reference":null,"responses":[{"text":"Biguanides","correct":false,"visible":false},{"text":"Thiazolidinediones","correct":true,"visible":false},{"text":"DPP-4 inhibitors","correct":false,"visible":false},{"text":"Meglitinides","correct":false,"visible":false},{"text":"GLP-1 analogs","correct":false,"visible":false}]},{"id":3302,"text":"Which hormone is responsible for the rapid supply of glucose in hypoglycemic conditions?","explanation":null,"reference":null,"responses":[{"text":"Cortisol","correct":false,"visible":false},{"text":"Insulin","correct":false,"visible":false},{"text":"Estrogen","correct":false,"visible":false},{"text":"Aldosterone","correct":false,"visible":false},{"text":"Glucagon","correct":true,"visible":false}]},{"id":3303,"text":"The pancreatic tail is present anterior to which structure?","explanation":"The **pancreas** is a glandular organ that plays a crucial role in digestion and glucose regulation. It is located in the upper abdomen, posterior to the stomach and adjacent to several other structures.\r\n\r\nThe pancreas has three main regions: the head, body, and tail. The **pancreatic tail** is the leftmost portion of the pancreas and is located in the left upper quadrant of the abdomen. It lies **anterior** (in front of) to the **left kidney**.","reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Philadelphia, MO: Elsevier; 2020: 332.","responses":[{"text":"Esophagus","correct":false,"visible":false},{"text":"Right kidney","correct":false,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Sigmoid colon","correct":false,"visible":false},{"text":"Left kidney","correct":true,"visible":false}]},{"id":3304,"text":"A nurse was brought to the emergency with hypoglycemia. Investigations were carried out, which showed high insulin levels with decreased C-peptide. Which of the following is mostly likely responsible for hypoglycemia?","explanation":null,"reference":null,"responses":[{"text":"Insulinoma","correct":false,"visible":false},{"text":"Endogenous physiological insulin production","correct":false,"visible":false},{"text":"Sulfonylurea drug","correct":false,"visible":false},{"text":"Exogenous insulin","correct":true,"visible":false},{"text":"Metformin","correct":false,"visible":false}]},{"id":3305,"text":"Without insulin, glucose can be transported into which of the following structures?","explanation":null,"reference":null,"responses":[{"text":"Adipose stores","correct":false,"visible":false},{"text":"Neurons","correct":true,"visible":false},{"text":"Striated muscle","correct":false,"visible":false},{"text":"Fat cells","correct":false,"visible":false},{"text":"Myocytes","correct":false,"visible":false}]},{"id":3306,"text":"Phentolamine is used to reduce hypertension in which of these?","explanation":null,"reference":null,"responses":[{"text":"Pheochromocytoma","correct":true,"visible":false},{"text":"Diabetes mellitus","correct":false,"visible":false},{"text":"Hypercholesterolemia","correct":false,"visible":false},{"text":"Metabolic syndrome","correct":false,"visible":false},{"text":"Hypocholesterolemia","correct":false,"visible":false}]},{"id":3307,"text":"What type of pancreatic cell is most abundant?","explanation":null,"reference":null,"responses":[{"text":"None of these","correct":false,"visible":false},{"text":"PP cells","correct":false,"visible":false},{"text":"Beta cells","correct":true,"visible":false},{"text":"Delta cells","correct":false,"visible":false},{"text":"Alpha cells","correct":false,"visible":false}]},{"id":3308,"text":"Which pair of hormonal levels will be found in a runner after a marathon?","explanation":null,"reference":null,"responses":[{"text":"Low insulin, low glucagon","correct":false,"visible":false},{"text":"High insulin, low glucagon","correct":false,"visible":false},{"text":"Low insulin, high glucagon","correct":true,"visible":false},{"text":"High insulin, high glucagon","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":3309,"text":"Most of the T3 hormone is synthesized by which of the following?","explanation":null,"reference":null,"responses":[{"text":"Reduction of T4","correct":false,"visible":false},{"text":"Reiodination of T4","correct":false,"visible":false},{"text":"Oxidation of T4","correct":false,"visible":false},{"text":"Decarboxylation of T4","correct":false,"visible":false},{"text":"Deiodination of T4","correct":true,"visible":false}]},{"id":3310,"text":"What is the structure of the insulin receptor?","explanation":null,"reference":null,"responses":[{"text":"2 alpha and 2 beta chains","correct":true,"visible":false},{"text":"2 alpha and 1 beta chain","correct":false,"visible":false},{"text":"1 alpha and 2 beta chains","correct":false,"visible":false},{"text":"1 alpha and 1 beta chain","correct":false,"visible":false},{"text":"2 alpha and 2 sigma chains","correct":false,"visible":false}]},{"id":3311,"text":"Which of the following insulin preparations is short-acting insulin?","explanation":null,"reference":null,"responses":[{"text":"Detemir","correct":false,"visible":false},{"text":"Regular insulin","correct":true,"visible":false},{"text":"Aspart","correct":false,"visible":false},{"text":"Lispro","correct":false,"visible":false},{"text":"Glulisine","correct":false,"visible":false}]},{"id":3312,"text":"The pancreas is found in what abdominal region?","explanation":null,"reference":null,"responses":[{"text":"Umblical and hypogastric","correct":false,"visible":false},{"text":"Epigastrium and right hypochondrium","correct":false,"visible":false},{"text":"Left lumbar and left iliac","correct":false,"visible":false},{"text":"Epigastrium and left hypochondrium","correct":true,"visible":false},{"text":"Left hypochondrium and left lumbar","correct":false,"visible":false}]},{"id":3313,"text":"What is the HbA1c cut-off for diabetes mellitus diagnosis?","explanation":null,"reference":null,"responses":[{"text":"\u003e6.5%","correct":true,"visible":false},{"text":"\u003e10%","correct":false,"visible":false},{"text":"\u003e9%","correct":false,"visible":false},{"text":"\u003e2.5%","correct":false,"visible":false},{"text":"\u003e1%","correct":false,"visible":false}]},{"id":3314,"text":"What is the required daily iodine intake for adults?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 8th ed. Wolters Kluwer; 2020: 399.","responses":[{"text":"70 micrograms","correct":false,"visible":false},{"text":"270 micrograms","correct":false,"visible":false},{"text":"150 micrograms","correct":true,"visible":false},{"text":"240 micrograms","correct":false,"visible":false},{"text":"100 micrograms","correct":false,"visible":false}]},{"id":3315,"text":"What is added to the diet in order to overcome iodine deficiency?","explanation":null,"reference":null,"responses":[{"text":"Iodized water","correct":false,"visible":false},{"text":"Iodized drug","correct":false,"visible":false},{"text":"Iodized salt","correct":true,"visible":false},{"text":"Regular salt","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":3316,"text":"How much iodine is present in the salt?","explanation":null,"reference":null,"responses":[{"text":"60-70 mg of iodine per kg of salt","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"20-40 mg of iodine per kg of salt","correct":true,"visible":false},{"text":"90-100 mg of iodine per kg of salt","correct":false,"visible":false},{"text":"0-10 mg of iodine per kg of salt","correct":false,"visible":false}]},{"id":3317,"text":"Which one of the following represents iodine in parts per million (ppm) at the production site?","explanation":null,"reference":null,"responses":[{"text":"50 ppm","correct":false,"visible":false},{"text":"30 ppm","correct":true,"visible":false},{"text":"70 ppm","correct":false,"visible":false},{"text":"100 ppm","correct":false,"visible":false},{"text":"10 ppm","correct":false,"visible":false}]},{"id":3318,"text":"Which of the following amino acid is required for the formation of thyroid hormones?","explanation":null,"reference":null,"responses":[{"text":"Glycine","correct":false,"visible":false},{"text":"Phenylalanine","correct":false,"visible":false},{"text":"Tryptophan","correct":false,"visible":false},{"text":"Tyrosine","correct":true,"visible":false},{"text":"Valine","correct":false,"visible":false}]},{"id":3319,"text":"Which of the following is not a consequence of iodine deficiency?","explanation":null,"reference":null,"responses":[{"text":"Endemic cretinism","correct":false,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Brain development problem","correct":false,"visible":false},{"text":"Hyperthyroidism","correct":true,"visible":false},{"text":"Reproductive failure","correct":false,"visible":false}]},{"id":3323,"text":"Memory related to general knowledge?","explanation":null,"reference":null,"responses":[{"text":"Autobiographical","correct":false,"visible":false},{"text":"Implicit","correct":false,"visible":false},{"text":"Procedural","correct":false,"visible":false},{"text":"Semantic","correct":true,"visible":false},{"text":"Episodic","correct":false,"visible":false}]},{"id":3324,"text":"A female presents to the outpatient department with a central neck mass above the hyoid bone, that moves on tongue protrusion. Which of the following will be the probable diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Thyroglossal duct cyst","correct":true,"visible":false},{"text":"Paraganglioma","correct":false,"visible":false},{"text":"Osteoporosis","correct":false,"visible":false},{"text":"Thyroid swelling (goiter)","correct":false,"visible":false},{"text":"Branchial cyst","correct":false,"visible":false}]},{"id":3325,"text":"In general adaptation syndrome, resistance to stress is decreased in which state?","explanation":null,"reference":null,"responses":[{"text":"Resistance stage","correct":false,"visible":false},{"text":"Fight and flight stage","correct":false,"visible":false},{"text":"Exhaustion stage","correct":true,"visible":false},{"text":"Defensive stage","correct":false,"visible":false},{"text":"Alarm stage","correct":false,"visible":false}]},{"id":3326,"text":"An earthquake survivor was rescued after 3 days. Vitals were stable and glucose level was measured to be 100mg/dl. What hormone kept the glucose level normal?","explanation":null,"reference":null,"responses":[{"text":"Cortisol","correct":false,"visible":false},{"text":"Growth hormone","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Glucagon","correct":true,"visible":false}]},{"id":3327,"text":"The thyroid hormone is mainly transported in blood by being bound to which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 944.","responses":[{"text":"Thyroid binding globulin","correct":true,"visible":false},{"text":"Transcortin","correct":false,"visible":false},{"text":"Albumin","correct":false,"visible":false},{"text":"Transthyretin","correct":false,"visible":false},{"text":"Remains unbound as free T3","correct":false,"visible":false}]},{"id":3328,"text":"Which of the following enzymes is needed to convert norepinephrine to epinephrine?","explanation":"The biosynthesis of epinephrine (adrenaline) from norepinephrine occurs in the adrenal medulla. The conversion is catalyzed by the enzyme **Phenylethanolamine N-methyltransferase (PNMT)**, which transfers a methyl group from S-adenosylmethionine to norepinephrine to form epinephrine.\r\n\r\nThe biosynthetic pathway for the synthesis of epinephrine is as follows:\r\n1. **Tyrosine Hydroxylase:** Converts the amino acid tyrosine to L-DOPA (dihydroxyphenylalanine).\r\n2. **DOPA Decarboxylase:** Converts L-DOPA to dopamine.\r\n3. **Dopamine Beta-Hydroxylase:** Converts dopamine to norepinephrine.\r\n4. **Phenylethanolamine N-methyltransferase (PNMT):** Converts norepinephrine to epinephrine.","reference":"Rodwell VW, Bender DA, Botham KM, Kennelly PJ, Weil PA. Harper’s Illustrated Biochemistry. 31st ed. McGraw-Hill Education; 2018: 739.","responses":[{"text":"Catechol-O-methyltransferase","correct":false,"visible":false},{"text":"DOPA hydroxylase","correct":false,"visible":false},{"text":"Tyrosine hydroxylase","correct":false,"visible":false},{"text":"Phenylethanolamine N-methyltransferase","correct":true,"visible":false},{"text":"Monoamine oxidase","correct":false,"visible":false}]},{"id":3329,"text":"In what ratio is c-peptide to insulin secreted?","explanation":null,"reference":null,"responses":[{"text":"2:1","correct":false,"visible":false},{"text":"3:1","correct":false,"visible":false},{"text":"1:2","correct":false,"visible":false},{"text":"1:1","correct":true,"visible":false},{"text":"1:3","correct":false,"visible":false}]},{"id":3330,"text":"What is referred to as a combination of Hashimoto thyroiditis and Addison's disease?","explanation":null,"reference":null,"responses":[{"text":"Schmidt syndrome","correct":true,"visible":false},{"text":"Autoimmune polyglandular syndrome Type I","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Pheochromocytoma","correct":false,"visible":false},{"text":"Pituitary adenoma","correct":false,"visible":false}]},{"id":3332,"text":"Glucose commonly enters a cell by what method?","explanation":null,"reference":null,"responses":[{"text":"Facilitated diffusion","correct":true,"visible":false},{"text":"Phagocytosis","correct":false,"visible":false},{"text":"Active transport","correct":false,"visible":false},{"text":"Simple diffusion","correct":false,"visible":false},{"text":"Pinocytosis","correct":false,"visible":false}]},{"id":3333,"text":"Parathyroid hormone, growth hormone-releasing hormone, and glucagon all use which signaling pathway?","explanation":"Parathyroid hormone (PTH), growth hormone-releasing hormone (GHRH), and glucagon are all peptide hormones that act on cell surface receptors and utilize the **cAMP (cyclic adenosine monophosphate) signaling pathway** to exert their effects.\r\n\r\nWhen these hormones bind to their respective receptors on the cell surface, it leads to the activation of a G-protein coupled receptor (GPCR). The activated GPCR then stimulates the production of cAMP from ATP by the enzyme adenylate cyclase. cAMP serves as a second messenger, activating protein kinase A (PKA), which phosphorylates various target proteins in the cell, leading to the cellular response to the hormone.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 924.","responses":[{"text":"IP3","correct":false,"visible":false},{"text":"Intracellular receptor","correct":false,"visible":false},{"text":"cGMP","correct":false,"visible":false},{"text":"cAMP","correct":true,"visible":false},{"text":"Receptor tyrosine kinase","correct":false,"visible":false}]},{"id":3334,"text":"Which of the following drugs activates the PPAR-gamma nuclear receptor?","explanation":null,"reference":null,"responses":[{"text":"Linagliptin","correct":false,"visible":false},{"text":"Metformin","correct":false,"visible":false},{"text":"Pioglitazone","correct":true,"visible":false},{"text":"Nateglinide","correct":false,"visible":false},{"text":"Glipizide","correct":false,"visible":false}]},{"id":3336,"text":"What hormone is most released in the post-absorptive state?","explanation":null,"reference":null,"responses":[{"text":"Cortisol","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false},{"text":"Glucagon","correct":true,"visible":false},{"text":"Thyroid hormone","correct":false,"visible":false},{"text":"Insulin","correct":false,"visible":false}]},{"id":3342,"text":"Which of the following plays a role in the hydrolysis of thyroglobulin to free active thyroid hormones?","explanation":null,"reference":null,"responses":[{"text":"All of these","correct":false,"visible":false},{"text":"Smooth endoplasmic reticulum","correct":false,"visible":false},{"text":"Iodide/chloride transporter","correct":false,"visible":false},{"text":"Lysosomes","correct":true,"visible":false},{"text":"Rough endoplasmic reticulum","correct":false,"visible":false}]},{"id":3343,"text":"A lean lady comes to the clinic with the complaint of fragility and irritability. On examination, her blood pressure is 90/60 mmHg. Her laboratory results show blood sugar 240 mg/dL. What test would you first suggest to be done?","explanation":null,"reference":null,"responses":[{"text":"ACTH","correct":true,"visible":false},{"text":"T4","correct":false,"visible":false},{"text":"Electrolytes","correct":false,"visible":false},{"text":"Cortisol","correct":false,"visible":false},{"text":"T3","correct":false,"visible":false}]},{"id":3344,"text":"Which of the following is an endocrine gland with cells abundant with secretory granules and colloids in the luminal area?","explanation":null,"reference":null,"responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Thyroid gland","correct":true,"visible":false},{"text":"Pancreas","correct":false,"visible":false},{"text":"Parathyroid gland","correct":false,"visible":false},{"text":"Adrenal gland","correct":false,"visible":false}]},{"id":3345,"text":"Which of the following is incorrect about the thyroid gland?","explanation":null,"reference":null,"responses":[{"text":"Supplied by the inferior thyroid artery","correct":false,"visible":false},{"text":"Has follicular and parafollicular cells","correct":false,"visible":false},{"text":"Only gland that causes storage of hormones outside","correct":false,"visible":false},{"text":"Synthesis of hormones occurs in follicular cells","correct":false,"visible":false},{"text":"None of them","correct":true,"visible":false}]},{"id":3346,"text":"Which of the following conditions causes amenorrhea, obesity, and constipation?","explanation":null,"reference":null,"responses":[{"text":"Hyperpituitarism","correct":false,"visible":false},{"text":"Hypothyroidism","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Hyperthyroidism","correct":false,"visible":false}]},{"id":3347,"text":"First-line therapy for prolactinoma is:","explanation":null,"reference":null,"responses":[{"text":"Octreotide","correct":false,"visible":false},{"text":"Metoclopramide","correct":false,"visible":false},{"text":"Acetazolamide","correct":false,"visible":false},{"text":"Dorzolamide","correct":false,"visible":false},{"text":"Bromocriptine","correct":true,"visible":false}]},{"id":3348,"text":"Which of these is the least frequent thyroid tumor?","explanation":null,"reference":null,"responses":[{"text":"Papillary","correct":false,"visible":false},{"text":"Medullary","correct":false,"visible":false},{"text":"Follicular","correct":false,"visible":false},{"text":"Anaplastic","correct":true,"visible":false},{"text":"Metastatic","correct":false,"visible":false}]},{"id":3349,"text":"Which of the following uses the second messenger cAMP mechanism?","explanation":null,"reference":null,"responses":[{"text":"Insulin","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Growth hormone","correct":false,"visible":false},{"text":"Oxytocin","correct":false,"visible":false},{"text":"Antidiuretic hormone","correct":true,"visible":false}]},{"id":3353,"text":"In diabetes mellitus, insulin deficiency causes which of the following effect?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 977.","responses":[{"text":"Increased rate of glycogen synthesis","correct":false,"visible":false},{"text":"Inhibition of hormone sensitive lipase","correct":false,"visible":false},{"text":"Increased uptake of glucose by muscles","correct":false,"visible":false},{"text":"Decreased glucose in blood","correct":false,"visible":false},{"text":"Decreased alpha glycerol phosphate in fat cells","correct":true,"visible":false}]},{"id":3358,"text":"What is the most common cause of Addison's disease in the West?","explanation":"Addison's disease, also known as primary adrenal insufficiency, is a condition characterized by the inadequate production of hormones by the adrenal glands. In the Western world, the most common cause of Addison's disease is autoimmune adrenalitis.\r\n\r\n**Autoimmune adrenalitis** occurs when the body's immune system mistakenly attacks and destroys the adrenal glands. This leads to a progressive loss of adrenal function and a decrease in the production of essential hormones, such as cortisol and aldosterone. Over time, the adrenal glands become smaller and may show signs of chronic inflammation.\r\n\r\nWhile tuberculosis used to be a common cause of Addison's disease in the past, particularly in developing countries, it has become less prevalent in the Western world due to improved healthcare and antibiotic treatments. Tumors of the adrenal gland, congenital absence of the adrenal gland, and infections are relatively rare causes of primary adrenal insufficiency compared to autoimmune adrenalitis.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1123.","responses":[{"text":"Infection","correct":false,"visible":false},{"text":"Autoimmune adrenalitis","correct":true,"visible":false},{"text":"Tumor of adrenal gland","correct":false,"visible":false},{"text":"Tuberculosis","correct":false,"visible":false},{"text":"Congenital absence of adrenal gland","correct":false,"visible":false}]},{"id":3359,"text":"Which of the following is not a symptom of hyperthyroidism?","explanation":null,"reference":null,"responses":[{"text":"Increase in body temperature","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Fine tremors","correct":false,"visible":false},{"text":"Tachycardia","correct":false,"visible":false},{"text":"Cold intolerance","correct":true,"visible":false}]},{"id":3360,"text":"A woman presented to the clinic with the complaint of weight loss despite having a good appetite, increased sweating, and oligomenorrhea. Her laboratory results show increased thyroid hormone levels in the body. Which of the following is the most likely cause for the woman's symptoms?","explanation":null,"reference":null,"responses":[{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Hyperthyroidism","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Hashimoto thyroiditis","correct":false,"visible":false},{"text":"Hyperparathyroidism","correct":false,"visible":false}]},{"id":3361,"text":"Which of the following lymph nodes do not drain the pancreas?","explanation":null,"reference":null,"responses":[{"text":"Celiac lymph nodes","correct":false,"visible":false},{"text":"Inferior mesenteric lymph nodes","correct":true,"visible":false},{"text":"Splenic lymph nodes","correct":false,"visible":false},{"text":"Pancreaticoduodenal lymph nodes","correct":false,"visible":false},{"text":"Superior mesenteric lymph nodes","correct":false,"visible":false}]},{"id":3362,"text":"Iodine is mainly excreted from the body through:","explanation":null,"reference":null,"responses":[{"text":"Saliva","correct":false,"visible":false},{"text":"Iodine is not excreted and is trapped inside the body","correct":false,"visible":false},{"text":"Urine","correct":true,"visible":false},{"text":"Faeces","correct":false,"visible":false},{"text":"Sweat","correct":false,"visible":false}]},{"id":3363,"text":"Which of the following is increased in hypothyroidism?","explanation":null,"reference":null,"responses":[{"text":"Blood flow to skin","correct":false,"visible":false},{"text":"Temperature","correct":false,"visible":false},{"text":"Basal metabolic rate","correct":false,"visible":false},{"text":"Cholesterol","correct":true,"visible":false},{"text":"Sweating","correct":false,"visible":false}]},{"id":3365,"text":"Which of the following is confirmatory for pheochromocytoma?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1129.","responses":[{"text":"Increased vanillylmandelic acid (VMA) and homovanillic acid (HVA) levels","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"High serum calcium levels","correct":false,"visible":false},{"text":"Increased T4 levels","correct":false,"visible":false},{"text":"Charcot-leyden crystals","correct":false,"visible":false}]},{"id":3368,"text":"Islets of Langerhans are mostly located in which portion of the pancreas?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 427.","responses":[{"text":"Centroacinar cells","correct":false,"visible":false},{"text":"Tail of the pancreas","correct":true,"visible":false},{"text":"Head of the pancreas","correct":false,"visible":false},{"text":"Uncinate process","correct":false,"visible":false},{"text":"Body of the pancreas","correct":false,"visible":false}]},{"id":3369,"text":"Which of the following is incorrect regarding the parathyroid gland?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 430.","responses":[{"text":"Derived from the third and fourth pharyngeal pouches","correct":false,"visible":false},{"text":"It has C-cells","correct":true,"visible":false},{"text":"Contains lymphocytes","correct":false,"visible":false},{"text":"Secretes PTH in response to decreased calcium","correct":false,"visible":false},{"text":"It has chief cells that secrete PTH","correct":false,"visible":false}]},{"id":3370,"text":"Which of the following disease is characterized by parathyroid hypoplasia and T cell deficiency?","explanation":null,"reference":null,"responses":[{"text":"Cri-du-chat (cat's cry) syndrome","correct":false,"visible":false},{"text":"Prader-Willi syndrome","correct":false,"visible":false},{"text":"Turner syndrome","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"DiGeorge  syndrome","correct":true,"visible":false}]},{"id":3371,"text":"Calcitonin is responsible for:","explanation":null,"reference":null,"responses":[{"text":"Increasing the plasma calcium levels","correct":false,"visible":false},{"text":"Increasing thyroxine levels","correct":false,"visible":false},{"text":"Decreasing the plasma calcium levels","correct":true,"visible":false},{"text":"Decreasing thyroxine levels","correct":false,"visible":false},{"text":"Increasing parathyroid hormone levels","correct":false,"visible":false}]},{"id":3383,"text":"Which of the following lies anterior to the left adrenal gland?","explanation":"**The pancreas lies anterior to the left adrenal gland.**\r\n\r\nThe pancreas is a dual-function organ with both endocrine and exocrine functions. It is located in the upper abdomen, behind the stomach and in front of the spine. The left adrenal gland is situated on top of the left kidney. Since the pancreas extends across the midline, the tail of the pancreas lies anterior to the left adrenal gland.\r\n\r\nIn contrast, the diaphragm is a dome-shaped muscle that separates the thoracic and abdominal cavities, and it lies superior to the left adrenal gland. The spleen is located on the left side of the abdomen, posterior to the stomach and anterior to the left kidney and adrenal gland. The liver is mainly situated on the right side of the abdomen, although a small portion, called the left lobe, extends across the midline and may be adjacent to the left adrenal gland.","reference":"Bashir O. Adrenal gland | radiology reference article | radiopaedia. Org. Radiopaedia. Accessed June 21, 2022. https://radiopaedia.org/articles/adrenal-gland","responses":[{"text":"All of them","correct":false,"visible":false},{"text":"Spleen","correct":false,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Pancreas","correct":true,"visible":false},{"text":"Diaphragm","correct":false,"visible":false}]},{"id":3384,"text":"A 32-year-old patient presented with a raised heart rate, profuse sweating, palpitations, and restlessness 2 months ago. His serum T3 and T4 were high and TSH was low. He had been getting treatment for his condition since then. Which follow-up tests should be performed?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 656.","responses":[{"text":"TRH levels","correct":false,"visible":false},{"text":"Repeat TSH","correct":false,"visible":false},{"text":"Repeat TSH and serum T3 and T4 levels","correct":true,"visible":false},{"text":"Serum T3 and T4 levels","correct":false,"visible":false},{"text":"Free serum T3","correct":false,"visible":false}]},{"id":3385,"text":"The receptors for binding of protein hormones are located on/in what structure?","explanation":null,"reference":null,"responses":[{"text":"Mitochondria","correct":false,"visible":false},{"text":"Rough endoplasmic reticulum","correct":false,"visible":false},{"text":"Cell surface membrane","correct":true,"visible":false},{"text":"Nucleus","correct":false,"visible":false},{"text":"Golgi body","correct":false,"visible":false}]},{"id":3386,"text":"What happens to osmolality and serum sodium levels, respectively, in diabetes insipidus?","explanation":null,"reference":null,"responses":[{"text":"Increase, decrease","correct":false,"visible":false},{"text":"Decrease, increase","correct":false,"visible":false},{"text":"Increase, increase","correct":true,"visible":false},{"text":"Decrease, decrease","correct":false,"visible":false},{"text":"Both are unaffected","correct":false,"visible":false}]},{"id":3387,"text":"An excess of growth hormone in childhood leads to what pathology?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1072.","responses":[{"text":"Acromegaly","correct":false,"visible":false},{"text":"Retinal detachment","correct":false,"visible":false},{"text":"Myxedema coma","correct":false,"visible":false},{"text":"Gigantism","correct":true,"visible":false},{"text":"Cushing disease","correct":false,"visible":false}]},{"id":3388,"text":"What is nephrocalcinosis?","explanation":null,"reference":null,"responses":[{"text":"Calcification of lower respiratory tract","correct":false,"visible":false},{"text":"Calcification of renal structures","correct":true,"visible":false},{"text":"Lipid deposits in renal structure","correct":false,"visible":false},{"text":"Calcification of myocardium","correct":false,"visible":false},{"text":"Lyonisation of DNA","correct":false,"visible":false}]},{"id":3389,"text":"In which of the following conditions thyroid-stimulating hormone (TSH) is not responsive to thyroid-releasing hormone (TRH)?","explanation":null,"reference":null,"responses":[{"text":"Tertiary hypothyroidism","correct":false,"visible":false},{"text":"Primary hypothyroidism","correct":false,"visible":false},{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Secondary hypothyroidism","correct":true,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":3390,"text":"Parathyroid veins drain into:","explanation":null,"reference":null,"responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Superior thyroid vein only","correct":false,"visible":false},{"text":"Superior, middle and inferior thyroid vein","correct":true,"visible":false},{"text":"Inferior thyroid only","correct":false,"visible":false},{"text":"Middle thyroid vein only","correct":false,"visible":false}]},{"id":3391,"text":"Receptors for steroid hormone are found in:","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 920.","responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Both nucleus and cytoplasm","correct":true,"visible":false},{"text":"Plasma membranes","correct":false,"visible":false},{"text":"Nucleus","correct":false,"visible":false},{"text":"Cytoplasm","correct":false,"visible":false}]},{"id":3392,"text":"Pheochromocytoma is a neoplasm that secretes which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1127.","responses":[{"text":"All of them","correct":false,"visible":false},{"text":"Cortisol","correct":false,"visible":false},{"text":"Aldosterone","correct":false,"visible":false},{"text":"Adrenaline","correct":true,"visible":false},{"text":"Sex hormones","correct":false,"visible":false}]},{"id":3393,"text":"Deficiency of which of the following hormone causes the life-threatening conditions?","explanation":null,"reference":null,"responses":[{"text":"Aldosterone","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Cortisol","correct":true,"visible":false},{"text":"Testosterone","correct":false,"visible":false},{"text":"Adrenaline","correct":false,"visible":false}]},{"id":3394,"text":"The most common site for neural crest tumor in children is:","explanation":null,"reference":null,"responses":[{"text":"Spinal cord","correct":false,"visible":false},{"text":"Kidney","correct":false,"visible":false},{"text":"Pancreas","correct":false,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Adrenal gland","correct":true,"visible":false}]},{"id":3395,"text":"Which of the following is seen in Addison's disease?","explanation":null,"reference":null,"responses":[{"text":"None of them","correct":false,"visible":false},{"text":"Decrease in both aldosterone and cortisol","correct":true,"visible":false},{"text":"Increase in cortisol","correct":false,"visible":false},{"text":"Hypertension","correct":false,"visible":false},{"text":"Decrease in cortisol","correct":false,"visible":false}]},{"id":3396,"text":"Chromium salts stain the adrenal gland due to the presence of which of the following?","explanation":null,"reference":null,"responses":[{"text":"Only epinephrine in adrenal medulla","correct":false,"visible":false},{"text":"All catecholamines in adrenal medulla","correct":true,"visible":false},{"text":"Only aldosterone in adrenal cortex","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Only cortisol in adrenal cortex","correct":false,"visible":false}]},{"id":3397,"text":"Which of the following pituitary hormone is responsible for the regulation of aldosterone?","explanation":null,"reference":null,"responses":[{"text":"Luteinizing hormone","correct":false,"visible":false},{"text":"None of these","correct":true,"visible":false},{"text":"Follicle-stimulating hormone","correct":false,"visible":false},{"text":"Thyroid-stimulating hormone","correct":false,"visible":false},{"text":"Growth hormone","correct":false,"visible":false}]},{"id":3398,"text":"Which of the following enzymes is inhibited by glucocorticoids?","explanation":null,"reference":null,"responses":[{"text":"Histidine decarboxylase","correct":false,"visible":false},{"text":"Phospholipase A2","correct":true,"visible":false},{"text":"Xanthine oxidase","correct":false,"visible":false},{"text":"Cyclooxygenase","correct":false,"visible":false},{"text":"5-lipooxygenase","correct":false,"visible":false}]},{"id":3399,"text":"Which of the following statement is wrong about the location of the left adrenal gland?","explanation":null,"reference":null,"responses":[{"text":"It is intraperitoneal","correct":true,"visible":false},{"text":"It lies opposite the vertebral level of 11th intercostal space","correct":false,"visible":false},{"text":"It is separated from kidney by perirenal fat","correct":false,"visible":false},{"text":"Pancreas lie anterior to it","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":3400,"text":"Which of the following is affected by the pituitary tumors to cause an increase in cortisol?","explanation":null,"reference":null,"responses":[{"text":"Somatotrophs","correct":false,"visible":false},{"text":"Gonadotrophs","correct":false,"visible":false},{"text":"Lactotrophs","correct":false,"visible":false},{"text":"Corticotrophs","correct":true,"visible":false},{"text":"Thyrotrophs","correct":false,"visible":false}]},{"id":3401,"text":"Which of the following is not associated with hyperparathyroidism?","explanation":null,"reference":null,"responses":[{"text":"Tetany","correct":true,"visible":false},{"text":"Calcium present in the urine","correct":false,"visible":false},{"text":"Osteitis fibrosa cystica","correct":false,"visible":false},{"text":"Hypophosphatemia","correct":false,"visible":false},{"text":"Hypercalcemia","correct":false,"visible":false}]},{"id":3402,"text":"Trousseau's sign is characterized by:","explanation":null,"reference":null,"responses":[{"text":"Carpopedal spasm","correct":true,"visible":false},{"text":"Contraction of facial muscles","correct":false,"visible":false},{"text":"Bronchospasm","correct":false,"visible":false},{"text":"Narrowing of pupil","correct":false,"visible":false},{"text":"All of these","correct":false,"visible":false}]},{"id":3403,"text":"Chovestek sign is characterized by:","explanation":null,"reference":null,"responses":[{"text":"Twitching of facial muscles","correct":true,"visible":false},{"text":"Increased reflexes","correct":false,"visible":false},{"text":"Extension of the arm","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Carpopedal spasm","correct":false,"visible":false}]},{"id":3404,"text":"Which of the following is wrong about the histology of oxyphil cells?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 15th ed. McGraw-Hill Medical; 2018: 434.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Acidophilic cytoplasm","correct":false,"visible":false},{"text":"Acidophilic cytoplasm due to glycogen","correct":true,"visible":false},{"text":"They are larger than principal cells","correct":false,"visible":false},{"text":"Acidophilic cytoplasm with abnormal shaped mitochondria","correct":false,"visible":false}]},{"id":3406,"text":"Stimulation of the adrenal medulla releases what two hormones?","explanation":null,"reference":null,"responses":[{"text":"Adrenaline/Aldosterone","correct":false,"visible":false},{"text":"Noradrenaline/cortisol","correct":false,"visible":false},{"text":"Adrenaline/Noradrenaline","correct":true,"visible":false},{"text":"Adrenaline/thyroxine","correct":false,"visible":false},{"text":"Noradrenaline/testesterone","correct":false,"visible":false}]},{"id":3407,"text":"Which of the following causes lead to muscle weakness in Conn syndrome?","explanation":"Conn syndrome, also known as primary hyperaldosteronism, is a disorder characterized by excessive production of aldosterone by the adrenal glands. Aldosterone plays a key role in the regulation of electrolyte balance in the body, particularly the retention of sodium and the excretion of potassium by the kidneys.\r\n\r\nIn Conn syndrome, the excessive aldosterone leads to **increased sodium reabsorption** and **potassium excretion** by the renal tubules. As a result, there is a net loss of potassium from the body, leading to **hypokalemia** (low blood potassium levels).\r\n\r\n**Muscle weakness** is a common clinical manifestation of hypokalemia. Potassium is essential for maintaining proper muscle function, including muscle contraction and relaxation. Low potassium levels disrupt the normal electrical activity of muscle cells, leading to weakness, fatigue, and sometimes even muscle cramps.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 960.","responses":[{"text":"Hypokalemia","correct":true,"visible":false},{"text":"Hypertension","correct":false,"visible":false},{"text":"Hypercalcemia","correct":false,"visible":false},{"text":"Hypernatremia","correct":false,"visible":false},{"text":"Neuropathy","correct":false,"visible":false}]},{"id":3408,"text":"What statement is incorrect regarding the pineal gland?","explanation":null,"reference":null,"responses":[{"text":"Surrounded by cerebrospinal fluid","correct":false,"visible":false},{"text":"Has brain sand (corpora arenacea)","correct":false,"visible":false},{"text":"Covered by pia matter","correct":false,"visible":false},{"text":"Substances released under the influence of hypothalamus","correct":false,"visible":false},{"text":"Pineal cells are known as chuff cells","correct":true,"visible":false}]},{"id":3410,"text":"The pancreas is referred to as a compound tubuloacinar gland. Which of the following best describes the word \"compound\"?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 86.","responses":[{"text":"Branched duct","correct":true,"visible":false},{"text":"Interlobular ducts","correct":false,"visible":false},{"text":"Branched secretory portion","correct":false,"visible":false},{"text":"All of them","correct":false,"visible":false},{"text":"Exocrine and endocrine parts","correct":false,"visible":false}]},{"id":3422,"text":"Neural crest cells are derived from:","explanation":null,"reference":null,"responses":[{"text":"Mesoderm","correct":false,"visible":false},{"text":"Endoderm","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Ectoderm and mesoderm","correct":false,"visible":false},{"text":"Ectoderm","correct":true,"visible":false}]},{"id":3423,"text":"What is the effect of exogenous corticosteroids on cortisol and adrenocorticotropic hormone (ACTH) respectively?","explanation":null,"reference":null,"responses":[{"text":"Decrease and increase","correct":false,"visible":false},{"text":"Both will increase","correct":false,"visible":false},{"text":"Increase and decrease","correct":false,"visible":false},{"text":"Increase and increase","correct":false,"visible":false},{"text":"Both will decrease","correct":true,"visible":false}]},{"id":3424,"text":"Which of the following is the ocular change in hypoparathyroidism?","explanation":null,"reference":null,"responses":[{"text":"Vision loss","correct":false,"visible":false},{"text":"Dryness","correct":false,"visible":false},{"text":"Cataract","correct":true,"visible":false},{"text":"Myopia","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":3425,"text":"Which of the following relates to the action of the parathyroid gland?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 433.","responses":[{"text":"Excretion of calcium from kidney","correct":false,"visible":false},{"text":"Absorption of calcium from kidneys and intestine","correct":true,"visible":false},{"text":"Storage of calcium in intestine","correct":false,"visible":false},{"text":"Absorption of phosphate from kidney","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":3431,"text":"Where are fenestrated capillaries present in parathyroid?","explanation":null,"reference":null,"responses":[{"text":"Parathyroid stroma","correct":true,"visible":false},{"text":"Thin capsule","correct":false,"visible":false},{"text":"Chief cells","correct":false,"visible":false},{"text":"Parathyroid parenchyma","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false}]},{"id":3432,"text":"Which of the following statement is incorrect regarding parathyroid histology?","explanation":null,"reference":null,"responses":[{"text":"Cytoplasm is eosinophilic","correct":false,"visible":false},{"text":"Stroma has reticular and collagen fibers","correct":false,"visible":false},{"text":"Separated from the thyroid by a thin capsule","correct":false,"visible":false},{"text":"Cytoplasm is basophilic","correct":true,"visible":false},{"text":"Stroma has fenestrated capillaries","correct":false,"visible":false}]},{"id":3433,"text":"What is the normal value level of calcium in the serum?","explanation":null,"reference":null,"responses":[{"text":"12 to 13 mg/dL","correct":false,"visible":false},{"text":"14 to 15 mg/dL","correct":false,"visible":false},{"text":"9 to 11 mg/dL","correct":true,"visible":false},{"text":"2-4 mg/dL","correct":false,"visible":false},{"text":"7 to 8 mg/dL","correct":false,"visible":false}]},{"id":3434,"text":"Which of the following leads to hypercalcemia?","explanation":null,"reference":null,"responses":[{"text":"Hypervitaminosis D","correct":true,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Hypoparathyroidism","correct":false,"visible":false},{"text":"Hypovitaminosis","correct":false,"visible":false}]},{"id":3435,"text":"Which of the following is incorrect regarding parathyroid hormone?","explanation":null,"reference":null,"responses":[{"text":"Increases calcium levels","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Essential for survival","correct":false,"visible":false},{"text":"Encapsulated","correct":false,"visible":false},{"text":"Derived from 2nd and 3rd pharyngeal arches","correct":true,"visible":false}]},{"id":3436,"text":"What is the correct statement for the histology of chief cells?","explanation":null,"reference":null,"responses":[{"text":"No granules","correct":false,"visible":false},{"text":"Darkly staining","correct":false,"visible":false},{"text":"Polygonal in shape","correct":true,"visible":false},{"text":"Basophilic cytoplasm","correct":false,"visible":false},{"text":"Lobed nuclei","correct":false,"visible":false}]},{"id":3437,"text":"Which of the following represents the metabolic function of the parathyroid gland?","explanation":null,"reference":null,"responses":[{"text":"Resorption of bone","correct":false,"visible":false},{"text":"All of them","correct":false,"visible":false},{"text":"Absorption of calcium","correct":false,"visible":false},{"text":"Absorption of phosphate","correct":false,"visible":false},{"text":"Activation of alpha-1-hydroxylase","correct":true,"visible":false}]},{"id":3438,"text":"Which of the following is involved in the synthesis of cortisol?","explanation":null,"reference":null,"responses":[{"text":"None of them","correct":false,"visible":false},{"text":"18-hydroxylase","correct":false,"visible":false},{"text":"5α-reductase","correct":false,"visible":false},{"text":"11β-hydroxylation","correct":true,"visible":false},{"text":"20-lyase","correct":false,"visible":false}]},{"id":3439,"text":"At which vertebral level is the adrenal gland found?","explanation":null,"reference":null,"responses":[{"text":"T3","correct":false,"visible":false},{"text":"L1","correct":false,"visible":false},{"text":"T12","correct":true,"visible":false},{"text":"L4","correct":false,"visible":false},{"text":"C5","correct":false,"visible":false}]},{"id":3440,"text":"Which of the following gland is large-sized at the time of birth?","explanation":null,"reference":null,"responses":[{"text":"Pancreas","correct":false,"visible":false},{"text":"Heart","correct":false,"visible":false},{"text":"Adrenal","correct":false,"visible":false},{"text":"Thymus","correct":true,"visible":false},{"text":"Brain","correct":false,"visible":false}]},{"id":3441,"text":"Adrenocortical therapy is not given in:","explanation":null,"reference":null,"responses":[{"text":"Primary adrenal insufficiency","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Addison's disease","correct":false,"visible":false},{"text":"Cushing disease","correct":true,"visible":false},{"text":"Secondary adrenal insufficiency","correct":false,"visible":false}]},{"id":3442,"text":"Which of the following will be seen in mineralocorticoid deficiency?","explanation":"Mineralocorticoids, such as aldosterone, are hormones produced by the adrenal glands that play a crucial role in the regulation of electrolyte balance, particularly sodium (Na) and potassium (K), in the body.\r\n\r\nIn mineralocorticoid deficiency, there is a lack of aldosterone, which leads to impaired reabsorption of sodium in the renal tubules. This results in **decreased reabsorption of Na** by the kidneys, leading to increased urinary excretion of Na. As a consequence, the body loses excess Na, and there is a decrease in extracellular fluid volume (hypovolemia) and blood pressure.\r\n\r\nFurthermore, with decreased aldosterone, there is also **reduced excretion of potassium** in the urine, leading to **hyperkalemia** (elevated blood potassium levels). The lack of aldosterone reduces the secretion of potassium into the urine, resulting in its accumulation in the blood.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 969.","responses":[{"text":"Decrease reabsorption of Na and K","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Decrease reabsorption of Ca and hypokalemia","correct":false,"visible":false},{"text":"Increase reabsorption of Na","correct":false,"visible":false},{"text":"Decrease reabsorption of Na and hyperkalemia","correct":true,"visible":false}]},{"id":3444,"text":"Which of the following corticosteroids is most important?","explanation":null,"reference":null,"responses":[{"text":"Aldosterone","correct":false,"visible":false},{"text":"All of them","correct":false,"visible":false},{"text":"Prednisone","correct":false,"visible":false},{"text":"Hydrocortisone","correct":false,"visible":false},{"text":"Cortisol","correct":true,"visible":false}]},{"id":3445,"text":"Which of the following layer of the adrenal cortex has numerous lipid droplets?","explanation":null,"reference":null,"responses":[{"text":"Zona reticularis","correct":false,"visible":false},{"text":"Zona glomerulosa","correct":false,"visible":false},{"text":"Zona reticularis and Zona glomerulosa","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Zona fasciculata","correct":true,"visible":false}]},{"id":3446,"text":"Which of the following enzymes are involved in steroidogenesis?","explanation":null,"reference":null,"responses":[{"text":"Lyase, hydroxylase and dehydrogenase","correct":true,"visible":false},{"text":"Hydroxylase and dehydrogenase only","correct":false,"visible":false},{"text":"Lyase only","correct":false,"visible":false},{"text":"Lyase and hydroxylase only","correct":false,"visible":false},{"text":"Hydroxylase only","correct":false,"visible":false}]},{"id":3447,"text":"Which of the following is correct regarding the cortisol's effect on carbohydrates?","explanation":null,"reference":null,"responses":[{"text":"Decreases gluconeogenesis","correct":false,"visible":false},{"text":"Increases glycogen formation","correct":false,"visible":false},{"text":"None of them","correct":false,"visible":false},{"text":"Uses glucogenic amino acids to form glucose","correct":true,"visible":false},{"text":"Uses lipofuscin to form glucose","correct":false,"visible":false}]},{"id":3475,"text":"Rapid calcium infusion leads to:","explanation":null,"reference":null,"responses":[{"text":"Myocardial infarction","correct":false,"visible":false},{"text":"Cardiac failure","correct":false,"visible":false},{"text":"Neurogenic shock","correct":false,"visible":false},{"text":"Hypercalcemia","correct":false,"visible":false},{"text":"Arrhythmia","correct":true,"visible":false}]},{"id":3476,"text":"A 36-year-old woman who was on medication for hyperthyroidism gives birth to a baby with fetal hypothyroidism. Which of the following drugs was she taking?","explanation":null,"reference":null,"responses":[{"text":"Propranolol","correct":false,"visible":false},{"text":"Atenolol","correct":false,"visible":false},{"text":"Penicillin","correct":false,"visible":false},{"text":"Warfarin","correct":false,"visible":false},{"text":"Carbimazole","correct":true,"visible":false}]},{"id":3493,"text":"A person with cardiovascular disease wants to decrease his low-density lipoprotein (LDL) cholesterol level. What would be the preferred suggestion?","explanation":"The preferred suggestion for a person with cardiovascular disease who wants to decrease their low-density lipoprotein (LDL) cholesterol level is **statins**.\r\n\r\nStatins, also known as HMG-CoA reductase inhibitors, are a class of drugs that effectively lower LDL cholesterol levels in the blood. They work by inhibiting the enzyme HMG-CoA reductase, which is involved in cholesterol synthesis. By reducing cholesterol production in the liver, statins lead to increased uptake and clearance of LDL cholesterol from the bloodstream, resulting in decreased LDL levels.\r\n\r\nNiacin and fibrates are also used to modify lipid levels, but they primarily target triglycerides and HDL cholesterol rather than LDL cholesterol. Exercise and weight loss can have some positive effects on cholesterol levels, but they are generally not as potent as statins in lowering LDL cholesterol and are often recommended as complementary lifestyle measures alongside medication.\r\n\r\nFor individuals with cardiovascular disease, statins are the first-line treatment to reduce LDL cholesterol and lower the risk of cardiovascular events.","reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 290.","responses":[{"text":"Statins","correct":true,"visible":false},{"text":"Niacin","correct":false,"visible":false},{"text":"Exercise","correct":false,"visible":false},{"text":"Fibrates","correct":false,"visible":false},{"text":"Weight loss","correct":false,"visible":false}]},{"id":3500,"text":"The pituitary fossa is a part of which bone?","explanation":null,"reference":null,"responses":[{"text":"Frontal","correct":false,"visible":false},{"text":"Nasal","correct":false,"visible":false},{"text":"Petrous temporal","correct":false,"visible":false},{"text":"Sphenoid","correct":true,"visible":false},{"text":"Ethmoid","correct":false,"visible":false}]},{"id":3518,"text":"Iodine is conjugated with which of the following in the thyroid gland?","explanation":null,"reference":null,"responses":[{"text":"Thyroid binding globulin","correct":false,"visible":false},{"text":"Immunoglobulin","correct":false,"visible":false},{"text":"Albumin","correct":false,"visible":false},{"text":"Thyroglobulin","correct":true,"visible":false},{"text":"Transthyretin","correct":false,"visible":false}]},{"id":3519,"text":"Hypopituitarism can result from hemorrhage into a pituitary adenoma. What is this condition known as?","explanation":null,"reference":null,"responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Sheehan syndrome","correct":false,"visible":false},{"text":"Craniopharyngioma","correct":false,"visible":false},{"text":"Empty sella syndrome","correct":false,"visible":false},{"text":"Pituitary apoplexy","correct":true,"visible":false}]},{"id":3520,"text":"A 30-year-old woman suffering from diabetes presents to the outpatient department with lightheadedness and bone pain. Her serum calcitonin and calcium levels are low and phosphate levels are high. What is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Anaplastic carcinoma","correct":false,"visible":false},{"text":"Follicuar thyroid carcinoma","correct":false,"visible":false},{"text":"Papillary thyroid carcinoma","correct":false,"visible":false},{"text":"Parathyroid carcinoma","correct":false,"visible":false},{"text":"Medullary thyroid carcinoma","correct":true,"visible":false}]},{"id":3521,"text":"A 56-year-old man presents to the outpatient department with pain in his phalanges. He is found to have high levels of parathyroid hormone and hypercalcemia. What is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Pagets disease","correct":false,"visible":false},{"text":"Oteitis fibrosa cystica","correct":true,"visible":false},{"text":"Vitamin D overload","correct":false,"visible":false},{"text":"Scurvy","correct":false,"visible":false},{"text":"Osteoporosis","correct":false,"visible":false}]},{"id":3524,"text":"Instead of taking insulin intravenously, a patient started taking insulin orally. Which of the following is most likely to happen?","explanation":null,"reference":null,"responses":[{"text":"Nausea","correct":false,"visible":false},{"text":"Persistent hypoglycemia","correct":false,"visible":false},{"text":"Hypoglycemia shock","correct":false,"visible":false},{"text":"Persistent hyperglycemia","correct":true,"visible":false},{"text":"Transient ischemic attack","correct":false,"visible":false}]},{"id":3527,"text":"Which of the following symptoms is associated with hypothyroidism?","explanation":"**Drowsiness** is associated with hypothyroidism.\r\n\r\nHypothyroidism is a condition characterized by an underactive thyroid gland, leading to decreased production of thyroid hormones. Thyroid hormones play a crucial role in regulating metabolism and various body functions. When their levels are low, it can result in a range of symptoms.\r\n\r\nDrowsiness or fatigue is a common symptom of hypothyroidism. Patients may feel excessively tired and lack energy despite getting enough sleep. Other common symptoms include weight gain, cold intolerance, constipation, dry skin, and hair loss.","reference":"(1) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 346.\r\n\r\n(2) Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1097.","responses":[{"text":"Tachycardia","correct":false,"visible":false},{"text":"Tachypnea","correct":false,"visible":false},{"text":"Hyperthermia","correct":false,"visible":false},{"text":"Drowsiness","correct":true,"visible":false},{"text":"Profuse sweating","correct":false,"visible":false}]},{"id":3529,"text":"Which of the following secretes melanin?","explanation":null,"reference":null,"responses":[{"text":"Hypothalamus","correct":false,"visible":false},{"text":"Intermediate lobe of the pituitary gland","correct":true,"visible":false},{"text":"Anterior lobe of the pituitary gland","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Posterior lobe of the pituitary gland","correct":false,"visible":false}]},{"id":3532,"text":"Which of the following is correct regarding growth hormone?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 934.","responses":[{"text":"Growth hormone is required for prenatal linear growth","correct":false,"visible":false},{"text":"Growth hormone is required for postnatal linear growth","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Growth hormone is required for postnatal horizontal growth","correct":false,"visible":false},{"text":"Thyroid hormone is essential for growth till puberty only","correct":false,"visible":false}]},{"id":3534,"text":"Which of the following is responsible for hyperpigmentation in Addisons disease?","explanation":null,"reference":null,"responses":[{"text":"Adrenocorticotropic hormone (ACTH)","correct":true,"visible":false},{"text":"Angiotensin","correct":false,"visible":false},{"text":"Corticotropin-releasing hormone (CRH)","correct":false,"visible":false},{"text":"Aldosterone","correct":false,"visible":false},{"text":"Cortisol","correct":false,"visible":false}]},{"id":3546,"text":"Which of the following does the hypothalamic nucleus supraoptic release?","explanation":null,"reference":null,"responses":[{"text":"Antidiuretic hormone (ADH)","correct":true,"visible":false},{"text":"Adrenocorticotropic hormone (ACTH)","correct":false,"visible":false},{"text":"Luteinizing hormone (LH)","correct":false,"visible":false},{"text":"Thyroid stimulating hormone (TSH)","correct":false,"visible":false},{"text":"Follicular stimulating hormone (FSH)","correct":false,"visible":false}]},{"id":3551,"text":"Which of the following is an action of insulin?","explanation":"**Increase K+ uptake** is an action of insulin.\r\n\r\nInsulin is a hormone produced by the beta cells of the pancreas and plays a critical role in regulating glucose metabolism. Its main function is to facilitate the uptake of glucose into cells, reducing blood glucose levels. However, insulin also has other important actions in the body.\r\n\r\nOne of these actions is the **stimulation of cellular uptake of potassium (K+)**. Insulin enhances the activity of the Na+/K+ ATPase pump on the cell membrane, which leads to increased uptake of potassium into cells. As a result, insulin helps lower the concentration of potassium in the bloodstream, maintaining proper potassium balance and preventing hyperkalemia.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 384.","responses":[{"text":"Decrease blood pH","correct":false,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"Increase Ca+ uptake","correct":false,"visible":false},{"text":"Increase K+ uptake","correct":true,"visible":false},{"text":"Increase Na+ uptake","correct":false,"visible":false}]},{"id":3552,"text":"Which of the following statements regarding the histology of the thyroid gland is true?","explanation":null,"reference":null,"responses":[{"text":"The gland is covered by a capsule made of loose connective tissue","correct":false,"visible":false},{"text":"Fenestrated capillaries are present in the interfollicular connective tissue","correct":true,"visible":false},{"text":"The connective tissue between the follicles is scanty","correct":false,"visible":false},{"text":"Parafollicular cells, like follicular cells, extend to the lumen of the follicles","correct":false,"visible":false},{"text":"Follicular cells have typical features of absorptive cells","correct":false,"visible":false}]},{"id":3553,"text":"Which of the following cells is destroyed in type 1 diabetes mellitus?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1099.","responses":[{"text":"Alpha cells","correct":false,"visible":false},{"text":"Pancreatic polypeptide cells (PP cells)","correct":false,"visible":false},{"text":"Delta cells","correct":false,"visible":false},{"text":"Beta cells","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":3554,"text":"Which of the following cells are polygonal and basophilic, with an eccentrically placed round nucleus and present in the pars distalis?","explanation":null,"reference":null,"responses":[{"text":"Thyrotropes","correct":false,"visible":false},{"text":"Gonadotropes","correct":false,"visible":false},{"text":"Corticotropes","correct":true,"visible":false},{"text":"Somatotropes","correct":false,"visible":false},{"text":"Lactotropes","correct":false,"visible":false}]},{"id":3555,"text":"Hürthle cells are present in which of the following?","explanation":null,"reference":null,"responses":[{"text":"Graves disease","correct":false,"visible":false},{"text":"De Quervain thyroiditis","correct":false,"visible":false},{"text":"Subacute lymphocytic thyroiditis","correct":false,"visible":false},{"text":"Hashimoto thyroiditis","correct":true,"visible":false},{"text":"Postpartum thyroiditis","correct":false,"visible":false}]},{"id":3556,"text":"Which of the following is an autoimmune disorder resulting in hyperthyroidism?","explanation":null,"reference":null,"responses":[{"text":"Graves disease","correct":true,"visible":false},{"text":"Hashimoto thyroiditis","correct":false,"visible":false},{"text":"Subacute lymphocytic thyroiditis","correct":false,"visible":false},{"text":"De Quervain thyroiditis","correct":false,"visible":false},{"text":"Postpartum thyroiditis","correct":false,"visible":false}]},{"id":3557,"text":"Which of the following will result from a lesion at the optic chiasma?","explanation":null,"reference":null,"responses":[{"text":"Homonymous quadrantanopia","correct":false,"visible":false},{"text":"Complete loss of vision","correct":false,"visible":false},{"text":"Homonymous hemianopsia","correct":false,"visible":false},{"text":"Heteronymous bitemporal hemianopia","correct":true,"visible":false},{"text":"Unilateral hemianopsia","correct":false,"visible":false}]},{"id":3558,"text":"Somatostatin inhibits which of the following hormones to decrease the pancreatic exocrine secretions?","explanation":null,"reference":null,"responses":[{"text":"Pancreatic polypeptide","correct":false,"visible":false},{"text":"Secretin","correct":false,"visible":false},{"text":"Cholecystokinin","correct":true,"visible":false},{"text":"Gastrin","correct":false,"visible":false},{"text":"Vasointestinal active peptide","correct":false,"visible":false}]},{"id":3559,"text":"Testosterone is produced under the control of which of the following hormones?","explanation":null,"reference":null,"responses":[{"text":"Human chorionic gonadotrophin","correct":false,"visible":false},{"text":"Adrenocorticotropic hormone","correct":false,"visible":false},{"text":"Luteinizing hormone","correct":true,"visible":false},{"text":"Follicle stimulating hormone","correct":false,"visible":false},{"text":"Growth hormone","correct":false,"visible":false}]},{"id":3560,"text":"A slide having three distinct zones, is shown to a student. Each zone has a different arrangement of cells but the cells of all three zones show an abundance of the smooth endoplasmic reticulum. Which region is shown in the slide?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 424.","responses":[{"text":"Parathyroid gland","correct":false,"visible":false},{"text":"Pancreas","correct":false,"visible":false},{"text":"Adrenal cortex","correct":true,"visible":false},{"text":"Adrenal medulla","correct":false,"visible":false},{"text":"Thyroid gland","correct":false,"visible":false}]},{"id":3561,"text":"A patient was diagnosed with Addison's disease. Which of the following would explain the symptom of orthostatic hypotension in this patient?","explanation":null,"reference":null,"responses":[{"text":"Hypoaldosteronism","correct":true,"visible":false},{"text":"Hypercortisolism","correct":false,"visible":false},{"text":"Hypoandrogenism","correct":false,"visible":false},{"text":"Hyperaldosteronism","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":3562,"text":"Which of the following is the active circulating thyroid hormone?","explanation":null,"reference":null,"responses":[{"text":"T3","correct":true,"visible":false},{"text":"Thyroid stimulating hormone","correct":false,"visible":false},{"text":"T4","correct":false,"visible":false},{"text":"Transthyretin","correct":false,"visible":false},{"text":"Thyroglubin","correct":false,"visible":false}]},{"id":3589,"text":"What is incorrect about insulin?","explanation":null,"reference":null,"responses":[{"text":"Insulin glargine is long acting","correct":false,"visible":false},{"text":"It can be synthesized synthetically","correct":false,"visible":false},{"text":"Insulin has 51 amino acids","correct":false,"visible":false},{"text":"Insulin has a short half life as well as long half life","correct":false,"visible":false},{"text":"Insulin can be given orally in diabetes","correct":true,"visible":false}]},{"id":3590,"text":"What kind of activity do the adrenal medulla hormones have?","explanation":null,"reference":null,"responses":[{"text":"Parasympathetic system like activity","correct":false,"visible":false},{"text":"Both sympathetic and parasympathetic system like activity","correct":false,"visible":false},{"text":"Sympathetic system like activity","correct":true,"visible":false},{"text":"Same as glucocorticoids","correct":false,"visible":false},{"text":"Stimulated by norepinephrine","correct":false,"visible":false}]},{"id":3592,"text":"Steroid hormones bind to which type of receptors?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 920.","responses":[{"text":"Cell surface receptors","correct":false,"visible":false},{"text":"G-protein linked couple receptor","correct":false,"visible":false},{"text":"Second messenger","correct":false,"visible":false},{"text":"Cytoplasmic receptors","correct":true,"visible":false},{"text":"Enzyme linked receptor","correct":false,"visible":false}]},{"id":19857,"text":"What is the recommended initial dose of levothyroxine for patients without ischemic heart disease who require thyroid hormone replacement?","explanation":null,"reference":"Davidson’s Principles and Practice of Medicine, 24th edition, page number: 640.","responses":[{"text":"100 micrograms","correct":true,"visible":false},{"text":"25 micrograms","correct":false,"visible":false},{"text":"50 micrograms","correct":false,"visible":false},{"text":"75 micrograms","correct":false,"visible":false},{"text":"15 micrograms","correct":false,"visible":false}]},{"id":19858,"text":"Which medical condition is known for causing an \"oast house smell\" in affected individuals?","explanation":null,"reference":"Mogilnicka I, Bogucki P, Ufnal M. Microbiota and malodor—etiology and management. International Journal of Molecular Sciences. Published April 20, 2020. Accessed December 11, 2023. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7215946/","responses":[{"text":"Phenylketonuria","correct":false,"visible":false},{"text":"Maple syrup urine disease","correct":false,"visible":false},{"text":"Diabetic ketoacidosis","correct":false,"visible":false},{"text":"Methionine malabsorption syndrome","correct":true,"visible":false},{"text":"Trimethylaminuria","correct":false,"visible":false}]},{"id":19880,"text":"Which of the following is the most likely cause of hirsutism in a patient with Cushing's syndrome?","explanation":null,"reference":"Hafsi W, Kaur J. Hirsutism. StatPearls. Published 2023. Accessed December 12, 2023. http://www.ncbi.nlm.nih.gov/books/NBK470417/","responses":[{"text":"Increased estrogen","correct":false,"visible":false},{"text":"Increased androgens","correct":true,"visible":false},{"text":"Increased progesterone","correct":false,"visible":false},{"text":"Increased cortisol","correct":false,"visible":false},{"text":"Decreased estrogen","correct":false,"visible":false}]},{"id":19893,"text":"If a patient taking spironolactone develops gynecomastia as an adverse effect, what is the recommended management?","explanation":null,"reference":"Davidson’s Principles and Practice of Medicine, 24th edition, page 643","responses":[{"text":"Reduce the dose of spironolactone","correct":false,"visible":false},{"text":"Switch to amiloride","correct":true,"visible":false},{"text":"Discontinue spironolactone and monitor for resolution","correct":false,"visible":false},{"text":"Perform surgery to remove excess breast tissue","correct":false,"visible":false},{"text":"Start androgen replacement","correct":false,"visible":false}]},{"id":19902,"text":"Which of the following conditions is commonly associated with hyperreflexia?","explanation":null,"reference":"https://www.ncbi.nlm.nih.gov/books/NBK482128/#:~:text=Severe%20cases%20of%20hypercalcemia%20can,non%2DPTH%2Dmediated%20causes.","responses":[{"text":"Hyponatremia","correct":false,"visible":false},{"text":"Hypocalcemia","correct":false,"visible":false},{"text":"Hypokalemia","correct":false,"visible":false},{"text":"Hypercalcemia","correct":true,"visible":false},{"text":"Hypoglycemia","correct":false,"visible":false}]}
]

